using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;

namespace project.DialogMnager
{
    using System.Collections.Generic;
    namespace бурмаджа_.dialogue

    {
        public class BaseText
        {
            private DialogueManager dm = new DialogueManager();

            public List<DialogueLine> GetDialog(int a)
            {
                return dm.GetDialog(a);
            }
            public BaseText()
            {
                DialogueLine a1 = new DialogueLine("Автор", "ХАНТАВИРУС: ЧЕРНОБЫЛЬСКАЯ ПЕТЛЯ", 0, 6); dm.AddText(a1, 0);
                DialogueLine a2 = new DialogueLine("Автор", "2067 год. Чернобыль. Восстановленный город.\nВертолёт МЧС приземлился на площадке у четвёртого энергоблока.\n" +
                    "\"Из него вышли четыре женщины в тактических куртках, с рюкзаками за плечами.\nЛучшие из лучших. Москва отправила их выяснить настоящую причину аварии 1986 года.\n" +
                    "Эмма, Диана, Роня и Динара знали друг друга не первый год.", 0, 6); dm.AddText(a2, 0);
                DialogueLine a3 = new DialogueLine("Автор", "Эмма — патологоанатом, тихая и наблюдательная.\nДиана — фельдшер скорой, лидер, холодная и рациональная.\nРоня — хирург, резкая, физически сильная, с револьвером в кобуре. Динара — медсестра, циничная, золотые руки.", 0, 6); dm.AddText(a3, 0);
                DialogueLine a4 = new DialogueLine("Автор", "Никто туда не спускался полвека. Спуститься предстоит им.\nОни вошли внутрь.", 0, 6); dm.AddText(a4, 0);
                DialogueLine a5 = new DialogueLine("Автор", "ПОДВАЛ ЭНЕРГОБЛОКА", 0, 0); dm.AddText(a5, 0);
                DialogueLine a6 = new DialogueLine("Автор", "Пахло бетонной пылью, старыми кабелями, сладковатой вонью формалина. Ступеньки уходили глубоко вниз.\nФонари выхватывали из тьмы ржавые трубы, облупившуюся краску.\n" +
                    "В конце спуска оказалась комната. Метров двадцать.", 0, 0); dm.AddText(a6, 0);
                DialogueLine a7 = new DialogueLine("Автор", "В центре — стальной стол. На столе — резная шкатулка из тёмного дерева.\nОна выглядила так, как будто бы её оставили здесь пару лет назад.", 0, 0); dm.AddText(a7, 0);
                DialogueLine a8 = new DialogueLine("Автор", "Эмма подошла первой. Открыла.\nВнутри, на выцветшем бархате, лежали советские армейские часы, намертво соединённые с православным крестом.\n" +
                    "Цепочка от часов обмотана вокруг креста, металл спекся воедино. Стрелки застыли на 26 апреля 1986 года, 01:23.", 0, 0); dm.AddText(a8, 0);
                DialogueLine a9 = new DialogueLine("Динара", "Момент взрыва", 21, 0); dm.AddText(a9, 0);
                DialogueLine a10 = new DialogueLine("Диана", "Не трогай", 9, 0); dm.AddText(a10, 0);
                DialogueLine a11 = new DialogueLine("Автор", "предупредила девушка с косичками\nНо Эмма уже взяла часы в руки. Металл был ледяным.\n" +
                    "Она повернула стрелки вспять — на несколько дней, до 20 апреля. Просто чтобы посмотреть.", 0, 0); dm.AddText(a11, 0);
                DialogueLine a12 = new DialogueLine("Автор", "Часы затикали. Крест нагрелся. Воздух задрожал.\nВспышка. Провал.", 0, 0); dm.AddText(a12, 0);
                DialogueLine a13 = new DialogueLine("Автор", "1986 год. Та же ночь. Тот же подвал.", 0, 0); dm.AddText(a13, 0);
                DialogueLine a14 = new DialogueLine("Автор", "Они упали на бетонный пол. Но запах изменился — вместо пыли гарь, мазут, формалин.\nЗа окном — темнота, собачий лай, и где-то далеко гул грузовиков.", 0, 0); dm.AddText(a14, 0);
                DialogueLine a15 = new DialogueLine("Роня", "Это не наш Чернобыль", 0, 0); dm.AddText(a15, 0);
                DialogueLine a16 = new DialogueLine("Автор", "Их заметил охранник. Крикнул, засвистел. Забегали тени.\nДевушки бросились бежать. Через ограду, через пустырь, через колючую проволоку.\n" +
                    "Голоса стихли только у старого облупленного здания — бывшей лаборатории рядом с ЧАЭС.\nВнутри темно, холодно, разбитые окна.", 0, 0); dm.AddText(a16, 0);
                DialogueLine a17 = new DialogueLine("Диана", "Разделимся, обыщем здание", 6, 0); dm.AddText(a17, 0);
                DialogueLine a18 = new DialogueLine("Автор", "Подвал лаборатории.", 0, 0); dm.AddText(a18, 0);
                DialogueLine a19 = new DialogueLine("Автор", "В подвале было сыро.\nСвет фонаря скользнул по ржавым трубам, стеллажам с пыльными склянками — и упёрся в скорченную фигуру в углу.\n" +
                    "Человек. Мужчина в лабораторном халате. Бледный, с запёкшейся кровью на губах.\nДышал с хрипом. Умирал.", 0, 0); dm.AddText(a19, 0);
                DialogueLine a20 = new DialogueLine("Автор", "Эмма действовала быстро. Рюкзак, аптечка из 2067 года — антибиотики, стимуляторы.\nНо этого мало. На стеллаже рядом с трупом стоял флакон.\n" +
                    "На этикетке — название, почти как у одного из её лекарств из будущего.\n«Пантостат-М».\nОна не задумалась. В лаборатории не хранят лекарств — но она не задумалась.\n" +
                    "Смешала содержимое флакона с препаратом из будущего и ввела человеку.", 0, 0); dm.AddText(a20, 0);
                DialogueLine a21 = new DialogueLine("Автор", "День первый.", 0, 0); dm.AddText(a21, 0);
                DialogueLine a22 = new DialogueLine("Автор", "На утро человеку стало хуже. Температура под сорок, бред, чёрная корка на губах.", 0, 0); dm.AddText(a22, 0);
                DialogueLine a23 = new DialogueLine("Динара", "Надо в больницу", 24, 0); dm.AddText(a23, 0);
                DialogueLine a24 = new DialogueLine("Автор", "Сказала медсестра, циничная, но сейчас в её голосе звучало непривычное беспокойство.", 0, 0); dm.AddText(a24, 0);
                DialogueLine a25 = new DialogueLine("Динара", "Он умрёт. Мы не можем просто сидеть.", 24, 0); dm.AddText(a25, 0);
                DialogueLine a26 = new DialogueLine("Роня", "Нет\nТы думаешь, в советской больнице нас встретят с распростёртыми объятиями?\nПосмотри на себя. На нашу одежду. На приборы в рюкзаках.\n" +
                    "Нас арестуют в первую же минуту.", 19, 0); dm.AddText(a26, 0);
                DialogueLine a27 = new DialogueLine("Диана", "Роня права. Я только что нашла газету. «Правда», 24 апреля 1986 года.\nМы в прошлом, Динара.\n" +
                    "И здесь нет наших законов. Если нас задержат — а задержат обязательно — допросы, КГБ, лагеря.\nНикто не узнает, где мы. Никто не придёт на помощь.", 6, 0); dm.AddText(a27, 0);
                DialogueLine a28 = new DialogueLine("Динара", "Но он же умирает", 24, 0); dm.AddText(a28, 0);
                DialogueLine a29 = new DialogueLine("Роня", "Он умирал и до того, как Эмма его нашла.\nМы зря вмешались. Наша обязанность — помогать, да.\n" +
                    "Но не ценой собственной жизни. И не ценой катастрофы,\nкоторую мы можем устроить, если раскроем себя.", 16, 0); dm.AddText(a29, 0);
                DialogueLine a30 = new DialogueLine("Диана", "Роня права насчёт второго\n\"Мы уже нарушили ход истории. Впутались туда, где нас быть не должно. Каждое лишнее действие — риск.\n" +
                    "Больница — это гарантированный провал. Нас запрут, а он всё равно умрёт.\nИли не умрёт — и тогда что?\nКак мы объясним его выздоровление советским врачам? Лекарствами из будущего, которых в природе не существует?", 0, 0); dm.AddText(a30, 0);
                DialogueLine a31 = new DialogueLine("Автор", "Динара замолчала. Она понимала, что они правы. Но цинизм не мог заглушить врачебную привычку.", 13, 0); dm.AddText(a31, 0);
                DialogueLine a32 = new DialogueLine("Динара", "И что нам делать?", 27, 0); dm.AddText(a32, 0);
                DialogueLine a33 = new DialogueLine("Роня", "Остаёмся здесь\nНаблюдаем. У него либо иммунитет сработает, либо нет.\nЕсли выживет — будем решать дальше. Если умрёт…\nпохороним и будем искать способ вернуться.", 16, 0); dm.AddText(a33, 0);
                DialogueLine a34 = new DialogueLine("Автор", "Эмма всё это время сидела на корточках рядом с человеком, не поднимая глаз.\nОна слышала каждый спор. Она знала, что они правы.\n" +
                    "Но смотреть на его лицо было невыносимо.", 0, 0); dm.AddText(a34, 0);
                DialogueLine a35 = new DialogueLine("Эмма", "Я остаюсь с ним\nБуду следить за температурой, давлением.\nЕсли станет совсем плохо…\nтогда подумаем про больницу. Но не раньше.", 4, 0); dm.AddText(a35, 0);
                DialogueLine a36 = new DialogueLine("Автор", "Диана посмотрела на неё долгим взглядом.", 0, 0); dm.AddText(a36, 0);
                DialogueLine a37 = new DialogueLine("Диана", "Но если он умрёт, мы уходим. Все.\nБез оглядки. И ты с нами.", 7, 0); dm.AddText(a37, 0);
                DialogueLine a38 = new DialogueLine("Динара", "А если выживет?", 21, 0); dm.AddText(a38, 0);
                DialogueLine a39 = new DialogueLine("Автор", "Никто не ответил.\nЭмма достала из рюкзака шкатулку — ту самую, которую нашла в подвале энергоблока.\n" +
                    "Открыла. Часы с крестом лежали на месте. Стрелки снова застыли на 26 апреля 1986 года.\nОна закрыла крышку и убрала шкатулку обратно.\nЧеловек застонал. На его губах выступила новая капля чёрной крови.", 0, 0); dm.AddText(a39, 0);
                DialogueLine a40 = new DialogueLine("Автор", "День второй. Утро.", 0, 0); dm.AddText(a40, 0);
                DialogueLine a41 = new DialogueLine("Автор", "Ночь прошла в тревожном забытьи.\nСпали по очереди: два человека на страже, два — на рюкзаках, подложив под головы свёрнутые лабораторные халаты.\n" +
                    "Эмма почти не сомкнула глаз — сидела рядом с пациентом, следила за пульсом, стирала чёрную корку с его губ.\nК утру температура немного спала. Но ненадолго.", 0, 0); dm.AddText(a41, 0);
                DialogueLine a42 = new DialogueLine("Диана", "Надо поесть\nМы ничего не ели со вчерашнего утра.\nА впереди неизвестно сколько.", 6, 0); dm.AddText(a42, 0);
                DialogueLine a43 = new DialogueLine("Автор", "У них были сухпайки. Компактные брикеты, которые разбухали в горячей воде, превращаясь в подобие каши или супа.\nИ горелка — маленькая, на химическом топливе, из того же армейского набора.", 0, 0); dm.AddText(a43, 0);
                DialogueLine a44 = new DialogueLine("Динара", "Костер разведём?", 27, 0); dm.AddText(a44, 0);
                DialogueLine a45 = new DialogueLine("Роня", "У нас нет дров", 16, 0); dm.AddText(a45, 0);
                DialogueLine a46 = new DialogueLine("Диана", "У нас есть горелка, идиоты\nНе в пещере живём.", 13, 0); dm.AddText(a46, 0);
                DialogueLine a47 = new DialogueLine("Автор", "Они нашли укромный угол в дальней части подвала — за бетонной колонной, где сквозняк тянул воздух вверх по вентиляционной шахте.\n" +
                    "Горелка зашипела, выпустив ровное синее пламя.\nДинара достала котелок, налила воды из своей фляги, бросила брикеты.\nЗапах еды — первый нормальный запах за два дня — разлился по подвалу.\n" +
                    "Эмма не подошла к костру. Она осталась у постели пациента.", 0, 0); dm.AddText(a47, 0);
                DialogueLine a48 = new DialogueLine("Роня", "Эм, иди сюда\nОн не умрёт за пять минут А ты выглядишь хуже его.", 16, 0); dm.AddText(a48, 0);
                DialogueLine a49 = new DialogueLine("Автор", "Эмма покачала головой. Но Диана подошла, взяла её за плечо и почти силой оттащила к огню.", 0, 0); dm.AddText(a49, 0);
                DialogueLine a50 = new DialogueLine("Диана", "Ешь. Приказ.\n", 10, 0); dm.AddText(a50, 0);
                DialogueLine a51 = new DialogueLine("Автор", "Эмма взяла кружку с горячей жижей. Вкуса не чувствовала.", 0, 0); dm.AddText(a51, 0);
                DialogueLine a52 = new DialogueLine("Автор", "День второй. Вечер.", 0, 0); dm.AddText(a52, 0);
                DialogueLine a53 = new DialogueLine("Автор", "Они обустроились.\nРасчистили угол, сложили рюкзаки в изголовье, натянули верёвку между трубами — повесили сушиться промокшие куртки.\n" +
                    "Динара нашла в лаборатории несколько старых хирургических халатов — ими укрылись на ночь.\nРоня отодрала от стены доску и сделала подобие стола.", 0, 0); dm.AddText(a53, 0);
                DialogueLine a54 = new DialogueLine("Динара", "Прям квартира", 22, 0); dm.AddText(a54, 0);
                DialogueLine a55 = new DialogueLine("Роня", "Дача мечты\nСо своим трупом в углу.", 17, 0); dm.AddText(a55, 0);
                DialogueLine a56 = new DialogueLine("Эмма", "Он не труп", 3, 0); dm.AddText(a56, 0);
                DialogueLine a57 = new DialogueLine("Роня", "Пока нет.\n", 17, 0); dm.AddText(a57, 0);
                DialogueLine a58 = new DialogueLine("Автор", "После ужина Диана достала карту — старую, советскую, нашла её в ящике стола вместе с какими-то протоколами.\nОни сидели у потухающей горелки, обсуждая, как попытаться вернуться.\n" +
                    "Шкатулка с часами лежала на импровизированном столе. Но пока никто не решался к ней прикасаться.", 0, 0); dm.AddText(a58, 0);
                DialogueLine a59 = new DialogueLine("Автор", "И тут пациент зашевелился. Сначала тихо застонал. Потом громче.\nЭмма вскочила первой.\nОн изогнулся дугой — и его вырвало.\n" +
                    "Чёрной, густой кровью. Она растеклась по полу под ним, воняя железом и ещё чем-то сладковатым, приторным.", 0, 0); dm.AddText(a59, 0);
                DialogueLine a60 = new DialogueLine("Динара", "Господи", 9, 0); dm.AddText(a60, 0);
                DialogueLine a61 = new DialogueLine("Роня", "Отойдите!", 18, 0); dm.AddText(a61, 0);
                DialogueLine a62 = new DialogueLine("Автор", "Она схватила Эмму за руку.", 0, 0); dm.AddText(a62, 0);
                DialogueLine a63 = new DialogueLine("Роня", "Не трогай его, Эмма. У него внутреннее кровотечение.", 19, 0); dm.AddText(a63, 0);
                DialogueLine a64 = new DialogueLine("Эмма", "Что делать?!", 5, 0); dm.AddText(a64, 0);
                DialogueLine a65 = new DialogueLine("Диана", "Ничего. Мы не в операционной.\nУ нас нет ни капельниц, ни препаратов, ни возможности сделать переливание.\nОн истекает кровью изнутри. Ему конец.", 9, 0); dm.AddText(a65, 0);
                DialogueLine a66 = new DialogueLine("Автор", "Пациент забился в конвульсиях, потом затих.\nДыхание стало поверхностным, почти неощутимым.", 0, 0); dm.AddText(a66, 0);
                DialogueLine a67 = new DialogueLine("Динара", "Надо было в больницу", 21, 0); dm.AddText(a67, 0);
                DialogueLine a68 = new DialogueLine("Роня", "В больнице ему бы поставили диагноз «неизвестная инфекция» и положили в изолятор\nА нас бы повязали в ту же минуту.\nТы это хочешь услышать?", 18, 0); dm.AddText(a68, 0);
                DialogueLine a69 = new DialogueLine("Динара", "Я и без тебя знаю.", 23, 0); dm.AddText(a69, 0);
                DialogueLine a70 = new DialogueLine("Автор", "Они замолчали. Эмма опустилась на колени рядом с человеком, взяла его за руку.\n Ладонь была ледяной. И тогда Динара произнесла то,\n о чём все думали, но боялись сказать", 0, 0); dm.AddText(a70, 0);
                DialogueLine a71 = new DialogueLine("Динара", "Мы говорили при нём. Вчера, когда он был в сознании. Помните?\n Я сказала «из 2067 года». Роня говорила про прошлое. Диана про КГБ. Он слышал.\n Если он выживет… что тогда?", 24, 0); dm.AddText(a71, 0);
                DialogueLine a72 = new DialogueLine("Роня", "Не выживет", 14, 0); dm.AddText(a72, 0);
                DialogueLine a73 = new DialogueLine("Динара", "А если?\n Если выживет — он будет знать про нас.\n Про будущее. Про то, откуда мы пришли\n И тогда нам придётся решать, что с ним делать.\n Убить?\n Ты это предлагаешь? ", 27, 0); dm.AddText(a73, 0);
                DialogueLine a74 = new DialogueLine("Диана", "Я предлагаю не загадывать.\n Пока он не выжил.", 6, 0); dm.AddText(a74, 0);
                DialogueLine a75 = new DialogueLine("Автор", "Эмма не обернулась. Она сжимала холодную ладонь умирающего и смотрела в потолок.", 0, 0); dm.AddText(a75, 0);
                DialogueLine a76 = new DialogueLine("Эмма", "Он выживет. Я сделаю так, чтобы он выжил.", 4, 0); dm.AddText(a76, 0);
                DialogueLine a77 = new DialogueLine("Роня", "Чем? У нас нет ничего.\nТолько твоя ошибка с лекарствами.", 16, 0); dm.AddText(a77, 0);
                DialogueLine a78 = new DialogueLine("Эмма", "Тогда я найду, чем.", 2, 0); dm.AddText(a78, 0);
                DialogueLine a79 = new DialogueLine("Автор", "В подвале стало тихо. Только горелка шипела, да где-то наверху ветер гулял по пустым коридорам лаборатории.\n А человек в углу снова застонал. ", 0, 0); dm.AddText(a79, 0);
                DialogueLine a80 = new DialogueLine("Автор", "День второй. Поздний вечер. Раздумья.\n Человек в углу метался в бреду. Чёрная корка на его губах треснула, и из трещины сочилась сукровица.\n Эмма сидела рядом, держа его за руку, но уже не пыталась измерить пульс — и так было ясно: сердце работало через раз.\n Остальные молча готовили нехитрый ужин.\n Динара грела воду на горелке, Роня размачивала сухпайки, Диана проверяла оружие.\n Никто не говорил вслух то, о чём все думали: он умирает, и ничем помочь нельзя.\n Эмма подняла глаза на стол, где лежала шкатулка. Та самая — тёмное дерево, потускневшая латунь.\n Внутри — часы с крестом. Ключ, который принёс их сюда.\n Может быть, он же и откроет дорогу назад.\n Она встала. Подошла к столу. Положила ладонь на крышку, но не открывала.", 0, 0); dm.AddText(a80, 0);
                DialogueLine a81 = new DialogueLine("Диана", "Ты что задумала?", 9, 0); dm.AddText(a81, 0);
                DialogueLine a82 = new DialogueLine("Эмма", "Часы.\n Если я поверну стрелки снова… может, мы вернёмся.\n Или хотя бы я.\n Возьму лекарства из будущего, настоящие, и приду обратно.\n Спасу его.", 4, 0); dm.AddText(a82, 0);
                DialogueLine a83 = new DialogueLine("Роня", "Эмма, это опасно.\n Мы не знаем, как это работает. В прошлый раз выбросило сюда.\n В следующий может выбросить в сорок первом. Или разорвать на атомы.\n", 19, 0); dm.AddText(a83, 0);
                DialogueLine a84 = new DialogueLine("Эмма", "А если не попробовать, он умрёт\n И мы останемся здесь навсегда.", 1, 0); dm.AddText(a84, 0);
                DialogueLine a85 = new DialogueLine("Динара", "Она права. Риск есть. Но что нам терять?\n У нас нет ни связи, ни карты, ни плана. Только эти часы.\n", 21, 0); dm.AddText(a85, 0);
                DialogueLine a86 = new DialogueLine("Диана", "И неизвестность. Ты готова к тому, что ничего не получится?\n Или станет хуже?", 7, 0); dm.AddText(a86, 0);
                DialogueLine a87 = new DialogueLine("Автор", "Эмма не ответила. Она открыла шкатулку. Часы лежали на бархате. Стрелки по-прежнему застыли на 26 апреля 1986, 01:23.\n Крест тускло блестел в свете горелки.", 0, 0); dm.AddText(a87, 0);
                DialogueLine a88 = new DialogueLine("Эмма", "Я попробую", 3, 0); dm.AddText(a88, 0);
                
                DialogueLine b1 = new DialogueLine("Автор", "Человек в углу дышал тяжело, но ровно. Чёрная корка на губах больше не росла. Он спал — или был без сознания, но живой.\n Эмма несколько раз проверила пульс: слабый, но есть.", 0, 0); dm.AddText(b1, 1);
                DialogueLine b2 = new DialogueLine("Эмма", "Мы не можем просто сидеть\n Часы принесли нас сюда. Может, они же смогут вернуть назад. Хотя бы меня. \n Я возьму лекарства из будущего, настоящие, и вернусь. Спасу его.", 3, 0); dm.AddText(b2, 1);
                DialogueLine b3 = new DialogueLine("Роня", "Опасно.", 18, 0); dm.AddText(b3, 1);
                DialogueLine b4 = new DialogueLine("Эмма", "Но надо попробовать.", 4, 0); dm.AddText(b4, 1);
                DialogueLine b5 = new DialogueLine("Автор", "Диана посмотрела на шкатулку, потом на пациента. Кивнула.", 0, 0); dm.AddText(b5, 1);
                DialogueLine b6 = new DialogueLine("Роня", "Попробуй. Но будь готова к тому, что ничего не выйдет.", 17, 0); dm.AddText(b6, 1);
                DialogueLine b7 = new DialogueLine("Автор", "Эмма открыла шкатулку. Часы с крестом лежали на бархате. \nСтрелки застыли на 26 апреля 1986, 01:23.\n Она взяла часы в руки — металл был ледяным.", 0, 0); dm.AddText(b7, 1);
                DialogueLine b8 = new DialogueLine("Эмма", "Поворачиваю.", 3, 0); dm.AddText(b8, 1);
                DialogueLine b9 = new DialogueLine("Автор", "Она перевела стрелки на 20 апреля — туда, откуда они пришли. Часы дёрнулись. \n Крест нагрелся. Раздался треск, как будто внутри ломались шестерёнки. \nВоздух задрожал — но не так сильно, как в прошлый раз. \nВспышка была слабой, почти незаметной. \nА затем — ничего. Часы затихли. Стрелки снова застыли на 26 апреля. \nКрест потускнел.", 0, 0); dm.AddText(b9, 1);
                DialogueLine b10 = new DialogueLine("Динара", "Не получилось.", 23, 0); dm.AddText(b10, 1);
                DialogueLine b11 = new DialogueLine("Автор", "Эмма попробовала ещё раз — перевела на 25 апреля, на 27, на любую дату. Часы не реагировали.", 0, 0); dm.AddText(b11, 1);
                DialogueLine b12 = new DialogueLine("Роня", "Либо одноразовые, Либо мы что-то делаем не так.", 14, 0); dm.AddText(b12, 1);
                DialogueLine b13 = new DialogueLine("Динара", "Или это не способ вернуться. А способ открыть что-то другое.", 27, 0); dm.AddText(b13, 1);
                DialogueLine b14 = new DialogueLine("Автор", "Они положили часы обратно в шкатулку. Человек в углу пошевелился, \nоткрыл глаза — мутные, но живые.", 0, 0); dm.AddText(b14, 1);
                DialogueLine b15 = new DialogueLine("Какой-то бедолага", "Не надо… \nНе крутите… без кода… сломаете…", 0, 0); dm.AddText(b15, 1);
                DialogueLine b16 = new DialogueLine("Автор", "Он снова потерял сознание.", 0, 0); dm.AddText(b16, 1);
                DialogueLine b17 = new DialogueLine("Эмма", "Код? Какой код?", 5, 0); dm.AddText(b17, 1);
                DialogueLine b18 = new DialogueLine("Автор", "Она подошла к пациенту, проверила пульс — жив. \nНащупала в кармане его халата блокнот. Тот самый, который потом они найдут.", 0, 0); dm.AddText(b18, 1);
                DialogueLine b19 = new DialogueLine("Эмма", "Здесь что-то есть,\n Рисунок. Цифры. 7, 3, 15. И церковь.", 2, 0); dm.AddText(b19, 1);
                DialogueLine b20 = new DialogueLine("Динара", "Значит, нам нужен ключ. \nНе просто повернуть стрелки, а повернуть их в правильном порядке.", 26, 0); dm.AddText(b20, 1);
                DialogueLine b21 = new DialogueLine("Роня", "И без этого мы не вернёмся и не спасём его.", 16, 0); dm.AddText(b21, 1);
                DialogueLine b22 = new DialogueLine("Автор", "Они посмотрели на пациента. Он был жив, но слаб. \nИм предстояло разгадать загадку. День третий. Утро\n За ночь пациент не умер. Он даже пришёл в себя на несколько минут, прошептал: \n«Церковь… улица Курчатова, 14… там ответы…» — и снова отключился.\nТеперь у них была цель: найти церковь, разгадать код 7-3-15 (или 15-3-7), \nпонять, как работают часы.\n Но встал вопрос: что делать с пациентом?", 0, 0); dm.AddText(b22, 1);
                DialogueLine b23 = new DialogueLine("Эмма", "Если мы все уйдём, он может умереть в одиночестве.", 5, 0); dm.AddText(b23, 1);
                DialogueLine b24 = new DialogueLine("Диана", "Если мы останемся здесь, мы никогда не узнаем, как вернуться.", 13, 0); dm.AddText(b24, 1);
                DialogueLine b25 = new DialogueLine("Эмма", "Я могу остаться с ним. А вы идите к церкви. Или наоборот.", 4, 0); dm.AddText(b25, 1);
                DialogueLine b26 = new DialogueLine("Автор", "Они замерли. Пациент застонал.", 0, 0); dm.AddText(b26, 1);
                
                DialogueLine endF1 = new DialogueLine("Автор", "Решение принято быстро, как приговор.", 0, 0); dm.AddText(endF1, 2);
                DialogueLine endF2 = new DialogueLine("Эмма", "Я остаюсь.", 3, 0); dm.AddText(endF2, 2);
                DialogueLine endF3 = new DialogueLine("Автор", "Эмма даже не смотрит на спор. Она сидит на корточках перед пациентом, \nперебирает ампулы в аптечке.", 0, 0); dm.AddText(endF3, 2);
                DialogueLine endF4 = new DialogueLine("Эмма", "У него пульс 120, давление падает. Без меня он не продержится и трёх часов.", 5, 0); dm.AddText(endF4, 2);
                DialogueLine endF5 = new DialogueLine("Автор", "Диана кивает — без лишних слов. Она уже застегнула куртку, проверила нож в голенище.", 0, 0); dm.AddText(endF5, 2);
                DialogueLine endF6 = new DialogueLine("Диана", "Мы идём на улицу Курчатова, 14. Находим церковь. Разгадываем код 7-3-15. Возвращаемся.\n Жди здесь. Роня, Динара — за мной.", 10, 0); dm.AddText(endF6, 2);
                DialogueLine endF7 = new DialogueLine("Автор", "Роня поправляет револьвер. Динара берёт второй фонарь. \nОни выходят в серый рассвет, и дверь лаборатории закрывается с глухим металлическим стуком. \nЭмма остаётся одна с умирающим. Она разворачивает импровизированную палату: \nгрелку с горячей водой под бок пациенту, подушку из свёрнутых халатов, капельницу — самодельную, \nиз шприца и трубки от системы. Вводит адреналин и антибиотик. Ничего не помогает. \nЕго температура снова ползёт вверх.\n А потом он открывает глаза.", 0, 0); dm.AddText(endF7, 2);
                DialogueLine endF8 = new DialogueLine("Автор", "Эмма бросает всё. Она нажимает на грудную клетку, сбивая ритм. \nВзгляд на монитор (если бы он был — но его нет, только пульс под пальцами, слабый, ниточка). \nПотом ещё укол — и вдруг его рука хватает её за запястье.\n Силой, которой не должно быть у умирающего.\n Он садится. Чёрная кровь больше не течёт изо рта. Она испаряется — превращается в маслянистый туман, \nкоторый втягивается обратно в его лёгкие с каждым вдохом. Кожа становится серой, \nкак бетон ЧАЭС. Глаза — мутные, с вертикальным зрачком. Не человеческим.\n Он встаёт. Эмма пятится к стене.\n Перед ней уже не человек. Голова наклонена к плечу, челюсть открыта — оттуда вырывается низкий, \nутробный стон. Глаза белые, без зрачков. \nОн не помнит её. Только голод. Он делает шаг. Медленный. Пальцы — серые, с чёрными ногтями — касаются её шеи. \nХолод обжигает.", 0, 0); dm.AddText(endF8, 2);
                DialogueLine endF9 = new DialogueLine("Эмма", "Какого...", 0, 0); dm.AddText(endF9, 2);
                DialogueLine endF10 = new DialogueLine("Автор", "Пальцы смыкаются. Хрящи хрустят. Она слышит этот звук прежде, чем чувствует боль. \nНоги подкашиваются, он приподнимает её над полом.\n В последнюю секунду она видит потолок, ржавую трубу — и шкатулку на столе. \nЧасы с крестом внутри. Стрелки дрогнули.", 0, 0); dm.AddText(endF10, 2);
                DialogueLine endF11 = new DialogueLine("Автор", "Хруст. Темнота.", 0, 0); dm.AddText(endF11, 2);
                
                DialogueLine z1 = new DialogueLine("Автор", "Дверь со скрипом приоткрылась. Внутри пахло ладаном, плесенью и чем-то сладковатым.", 0, 5); dm.AddText(z1, 3);
                DialogueLine z2 = new DialogueLine("Диана", "Заходим.", 10, 5); dm.AddText(z2, 3);
                DialogueLine z3 = new DialogueLine("Автор", "Эмма сжала шкатулку с часами и шагнула через порог.\n Ключ щёлкнул в замке. Дверь со скрипом отворилась, \nвыпустив наружу клуб сырого, спёртого воздуха.", 0, 1); dm.AddText(z3, 3);
                DialogueLine z4 = new DialogueLine("Диана", "Не торопись. Сначала свет.", 9, 1); dm.AddText(z4, 3);
                DialogueLine z5 = new DialogueLine("Автор", "Она достала фонарь, включила. Луч упёрся в тёмный прямоугольник проёма, \nскользнул по каменному полу, по стенам, по облупившимся фрескам.", 0, 1); dm.AddText(z5, 3);
                DialogueLine z6 = new DialogueLine("Роня", "Порог.", 17, 0); dm.AddText(z6, 3);
                DialogueLine z7 = new DialogueLine("Автор", "Эмма шагнула первой. Подошва хрустнула по битому стеклу. За ней — остальные.\n Дверь сама захлопнулась за их спинами, будто кто-то придержал её, а потом отпустил.\n Внутри было тихо. Слишком тихо. Луч фонаря выхватывал из темноты ветхость: \nполоманные скамьи, сорванные с петель царские врата, клочья ткани на аналое. \nПахло ладаном — не свежим, а старым, въевшимся, смешанным с плесенью и ещё чем-то сладковатым, тревожным.", 0, 1); dm.AddText(z7, 3);
                DialogueLine z8 = new DialogueLine("Динара", "Будто здесь кого-то хоронили.", 24, 1); dm.AddText(z8, 3);
                DialogueLine z9 = new DialogueLine("Роня", "Или отпевали живых.", 16, 1); dm.AddText(z9, 3);
                DialogueLine z10 = new DialogueLine("Автор", "Они пошли вдоль стены. Свет фонаря метался, рождая чудовищные тени. В углах темнота сгущалась.", 0, 1); dm.AddText(z10, 3);
                DialogueLine z11 = new DialogueLine("Диана", "Это место не просто заброшено. Его оставили в спешке. Взгляни.", 9, 1); dm.AddText(z11, 3);
                DialogueLine z12 = new DialogueLine("Автор", "Она подсветила пол. Следы — чёткие цепочки обуви, ведущие к алтарю и обратно. \nКто-то ходил здесь недавно.", 0, 1); dm.AddText(z12, 3);
                DialogueLine z13 = new DialogueLine("Динара", "Не нравится мне это. Как будто нас ждали.", 23, 1); dm.AddText(z13, 3);
                DialogueLine z14 = new DialogueLine("Эмма", "Может, и ждали.\n У нас есть код. У нас есть часы. \nВопрос — зачем всё это.", 3, 1); dm.AddText(z14, 3);
                DialogueLine z15 = new DialogueLine("Автор", "Она подняла фонарь к потолку. Там, на рёбрах сводов, виднелась фреска — Спаситель, \nно лик его был стёрт, а вместо глаз зияли две чёрные дыры.", 0, 1); dm.AddText(z15, 3);
                DialogueLine z16 = new DialogueLine("Диана", "Идём к алтарю. Там должно быть что-то главное.", 10, 1); dm.AddText(z16, 3);
                DialogueLine z17 = new DialogueLine("Автор", "Они двинулись вперёд, обходя рассыпанные по полу псалтыри и щепки.\n В алтарной части, на престоле, под слоем пыли, стояла ещё одна шкатулка — точная копия той, \nчто принесла Эмма. Динара открыла её. Внутри лежал конверт. \nЭмма разорвала его, вытащила пожелтевший листок.", 0, 1); dm.AddText(z17, 3);
                DialogueLine z18 = new DialogueLine("Эмма", "Здесь написано «Если вы читаете это — вы прошли код 7‑3‑15. \nЧасы открыли дверь. Теперь найдите свечи. Зажгите их в правильном порядке. \nТогда увидите путь. Он приведёт вас туда, где всё начинается. Ф.»", 2, 1); dm.AddText(z18, 3);
                DialogueLine z19 = new DialogueLine("Роня", "«Где всё начинается»? Что это значит?", 16, 1); dm.AddText(z19, 3);
                DialogueLine z20 = new DialogueLine("Эмма", "Не знаю.", 3, 1); dm.AddText(z20, 3);
                DialogueLine z21 = new DialogueLine("Эмма", "Возможно, то место, которое ищет наша команда. Причина аварии. \nИли что-то другое. Узнаем, когда найдём.", 1, 1); dm.AddText(z21, 3);
                DialogueLine z22 = new DialogueLine("Автор", "Они осмотрелись и заметили у правой стены невысокий столик. \nНа нём — три свечи: красная, белая, чёрная. Эмма поднесла фонарь к каждой. \nНа нижней части красной были едва заметно выцарапаны цифры \n«7», на белой — «3», на чёрной — «15».", 0, 1); dm.AddText(z22, 3);
                DialogueLine z23 = new DialogueLine("Диана", "Порядок?", 10, 1); dm.AddText(z23, 3);
                DialogueLine z24 = new DialogueLine("Автор", "Роня указала на колонну рядом со столиком. С обратной стороны иконы, которую она сняла, \nбыли нацарапаны римские цифры: VII, III, XV.", 0, 1); dm.AddText(z24, 3);
                DialogueLine z25 = new DialogueLine("Роня", "Судя по этой подсказке — сначала красная, потом белая, потом чёрная,", 18, 1); dm.AddText(z25, 3);
                DialogueLine z26 = new DialogueLine("Автор", "Эмма взяла старый коробок спичек, чиркнула. Зажгла красную свечу. \nПламя вспыхнуло ровно. Затем белую — спокойно. Затем чёрную.\n И в тот же миг воздух в церкви задрожал. Окна затянуло чернотой, будто кто-то выключил день за их спинами. \nПод ногами раздался глухой щелчок — плита пола у алтаря просела, открывая каменную лестницу, уходящую вниз. \nОттуда тянуло холодом и запахом сырой земли.", 0, 1); dm.AddText(z26, 3);
                DialogueLine z27 = new DialogueLine("Эмма", "Путь.", 3, 1); dm.AddText(z27, 3);
                DialogueLine z28 = new DialogueLine("Диана", "Туда, где всё начинается. Приготовьтесь. Что бы нас там ни ждало, \nэто только начало.", 10, 1); dm.AddText(z28, 3);
                DialogueLine z29 = new DialogueLine("Автор", "Она шагнула первой. Остальные — за ней.", 0, 1); dm.AddText(z29, 3);
                DialogueLine z30 = new DialogueLine("Автор", "Они спускались в темноту. Ступени были каменными, стёртыми до блеска — кто-то ходил здесь часто. Воздух становился тяжелее, холоднее, \nи к запаху земли примешивалось нечто новое — железо, старая кровь, химикаты.", 0, 1); dm.AddText(z30, 3);
                DialogueLine z31 = new DialogueLine("Диана", "Тише. Свет приглушите.", 9, 1); dm.AddText(z31, 3);
                DialogueLine z32 = new DialogueLine("Автор", "Она почти погасила фонарь, оставив лишь тусклую нить света. \nВнизу кто-то был. Слышались шаги, звяканье металла, приглушённая ругань. Они спустились до конца. \nЛестница вывела в просторное подвальное помещение — низкий сводчатый потолок, стены из грубого камня, пол бетонный. \nА в центре, у длинного стола, заваленного бумагами, колбами и инструментами, стоял человек. \nМолодой — лет двадцати шести. В чёрной рясе, поверх которой был надет грязный лабораторный халат. \nРусые волосы растрёпаны, пальцы в чём-то тёмном. \nОн что-то торопливо смешивал в пробирках, не глядя по сторонам, \nи бормотал себе под нос.", 0, 3); dm.AddText(z32, 3);
                DialogueLine z33 = new DialogueLine("Фалекс", "Быстрее… не успеваю… завтра уже поздно будет…", 29, 3); dm.AddText(z33, 3);
                DialogueLine z34 = new DialogueLine("Автор", "Он поднял голову и замер, увидев их.", 0, 3); dm.AddText(z34, 3);
                DialogueLine z35 = new DialogueLine("Фалекс", "Вы. А я думал, вы появитесь только завтра. Или послезавтра. \nЧасы сработали быстрее, чем я рассчитывал.", 35, 3); dm.AddText(z35, 3);
                DialogueLine z36 = new DialogueLine("Диана", "Кто вы?", 9, 3); dm.AddText(z36, 3);
                DialogueLine z37 = new DialogueLine("Фалекс", "Фалекс. Хозяин этой церкви. И, как вы уже догадались, \nтот, кто оставил вам шкатулку.", 30, 3); dm.AddText(z37, 3);
                DialogueLine z38 = new DialogueLine("Эмма", "Зачем?\n Зачем вы привели нас сюда?", 0, 3); dm.AddText(z38, 3);
                DialogueLine z39 = new DialogueLine("Автор", "Фалекс усмехнулся, но глаза остались пустыми.", 0, 3); dm.AddText(z39, 3);
                DialogueLine z40 = new DialogueLine("Фалекс", "Я не приводил. Вы пришли сами. Я лишь оставил ключи. Часы — только половина. \n Вторая половина здесь. Я искал способ остановить то, что должно случиться завтра. \nНо теперь… теперь у меня нет времени. А вы — моя ошибка \nили моё спасение. Ещё не решил.", 31, 3); dm.AddText(z40, 3);
                DialogueLine z41 = new DialogueLine("Роня", "Что случится завтра?", 19, 3); dm.AddText(z41, 3);
                DialogueLine z42 = new DialogueLine("Фалекс", "Взрыв. Четвёртый блок. Авария, которой не должно было быть. Но она будет. \nИ если я не успею…", 32, 3); dm.AddText(z42, 3);
                DialogueLine z43 = new DialogueLine("Фалекс", "Если я не успею, всё пойдёт не так. Или так, как надо — смотря для кого.", 29, 3); dm.AddText(z43, 3);
                DialogueLine z44 = new DialogueLine("Автор", "Он резко повернулся к ним.", 0, 3); dm.AddText(z44, 3);
                DialogueLine z45 = new DialogueLine("Фалекс", "У вас мало времени. Я отвечу на три вопроса. \nА потом вы поможете мне — или убирайтесь к чёрту. Выбирайте.", 35, 3); dm.AddText(z45, 3);
                DialogueLine q1 = new DialogueLine("Фалекс", "Пытаюсь остановить то, что сам же и начал. Смешиваю компоненты. \nИщу противоядие. Но времени почти не осталось.", 32, 3); dm.AddText(q1, 4);
                DialogueLine qq1 = new DialogueLine("Фалекс", "Часы — только ключ. Вам нужен второй артефакт, он в шахте под четвёртым блоком. \nБез него вы застрянете здесь навсегда.", 29, 3); dm.AddText(qq1, 5);
                DialogueLine qqq1 = new DialogueLine("Фалекс", "Я хотел вернуть её. Одну. А получилось, что ставлю под угрозу всех. \nТеперь я не знаю, как остановиться.", 33, 3); dm.AddText(qqq1, 6);
                DialogueLine qqqq1 = new DialogueLine("Фалекс", "Часы сами выбрали вас. Или время. Или Бог — не знаю. \nНо вы — единственные, кто может замкнуть петлю. Или разорвать её", 31, 3); dm.AddText(qqqq1, 7);
                DialogueLine z46 = new DialogueLine("Автор", "Фалекс замолчал, опустил пробирку на стол и посмотрел на них в упор. \nУсталый, злой, но не безумный — это почему-то пугало больше всего.", 0, 3); dm.AddText(z46, 3);
                DialogueLine z47 = new DialogueLine("Фалекс", "Я ответил на ваши вопросы. Теперь мой черёд.\n Завтра здесь всё рухнет. Реактор, город, надежда. Я пытаюсь это остановить, \nно один не справлюсь. Мне нужны руки, глаза, время. \nТо, чего у меня больше нет.", 35, 3); dm.AddText(z47, 3);
                DialogueLine z48 = new DialogueLine("Автор", "Пауза. В подвале было слышно, как потрескивает одна из свечей на столе.", 0, 3); dm.AddText(z48, 3);
                DialogueLine z49 = new DialogueLine("Фалекс", "Так что спрашиваю прямо: вы поможете мне? \nИли будете искать свой путь — и умрёте, даже не поняв, зачем сюда попали?", 31, 3); dm.AddText(z49, 3);
               
                DialogueLine c1 = new DialogueLine("Эмма", "Мы поможем.", 4, 3); dm.AddText(c1, 8);
                DialogueLine c2 = new DialogueLine("Автор", "сказала Эмма, посмотрев на остальных. Диана нехотя кивнула, \nРоня пожала плечами, Динара вздохнула, но не возражала.\n Фалекс коротко кивнул, не тратя времени на благодарности.", 0, 3); dm.AddText(c2, 8);
                DialogueLine c3 = new DialogueLine("Фалекс", "Мне нужен компонент. Он хранится в старом складе за церковью, \nв пяти минутах ходьбы. Без него ничего не приготовить. Идём.", 31, 3); dm.AddText(c3, 8);
                DialogueLine c4 = new DialogueLine("Автор", "Он скинул халат, оставшись в одной рясе, сунул за пояс револьвер и решительно направился к выходу. \nДевушки переглянулись — ничего не оставалось, кроме как идти за ним.\n Склад\n Здание оказалось полуразрушенным ангаром, \nкрыша местами провалилась, окна забиты досками. Фалекс открыл ржавым ключом тяжёлую дверь, \nи они шагнули внутрь. Пахло пылью, гнилью и чем-то сладковатым, тревожным.", 0, 2); dm.AddText(c4, 8);
                DialogueLine c5 = new DialogueLine("Фалекс", "В конце коридора.\n Там стеллаж с металлическим ящиком. Мне нужны ампулы внутри.", 29, 2); dm.AddText(c5, 8);
                DialogueLine c6 = new DialogueLine("Автор", "Он двинулся первым, но не успел сделать и десяти шагов.\n Из-за поворота вывалилась фигура. Человек — или то, что от него осталось. \nЛицо серое, глаза белые, ничего не видящие, с губ свисали кровавые нити слюны. \nОн закричал — горлом, не ртом — и бросился на Фалекса.\n Фалекс отшатнулся, выстрелил. Пуля попала твари в плечо, \nно та даже не замедлилась.", 0, 2); dm.AddText(c6, 8);
                DialogueLine c7 = new DialogueLine("Эмма", "Это он! Это тот человек! Тот, кого мы нашли в подвале! \nТот, кого я пыталась спасти!", 0, 2); dm.AddText(c7, 8);
                DialogueLine c8 = new DialogueLine("Фалекс", "Что? Вы нашли его? Живого?", 35, 2); dm.AddText(c8, 8);
                DialogueLine c9 = new DialogueLine("Диана", "Он умирал. Мы пытались помочь.", 6, 2); dm.AddText(c9, 8);
                DialogueLine c10 = new DialogueLine("Фалекс", "Зря. Зря.", 28, 2); dm.AddText(c10, 8);
                DialogueLine c11 = new DialogueLine("Автор", "Тварь снова бросилась вперёд. Роня выстрелила в упор — в голову. \nТело рухнуло на бетон и замерло. Тишина. Эмма смотрела на мёртвое лицо, и в голове не укладывалось: \nтот самый человек. Которого она вкалывала лекарством, за которым следила, \nкоторого хотела вытащить с того света. Теперь он лежал здесь, превратившись в нечто, \nи она сама добила его выстрелом.", 0, 2); dm.AddText(c11, 8);
                DialogueLine c12 = new DialogueLine("Роня", "Кто он?", 15, 2); dm.AddText(c12, 8);
                DialogueLine c13 = new DialogueLine("Автор", "Фалекс опустил револьвер. Его лицо ничего не выражало.", 0, 2); dm.AddText(c13, 8);
                DialogueLine c14 = new DialogueLine("Фалекс", "Мой бывший лаборант. Коля. \nЯ думал, он сбежал. Не знал, что он здесь.", 32, 2); dm.AddText(c14, 8);
                DialogueLine c15 = new DialogueLine("Эмма", "Вы его убили?", 5, 2); dm.AddText(c15, 8);
                DialogueLine c16 = new DialogueLine("Фалекс", "Я его подстрелил. Несколько дней назад. Он предал меня. Хотел забрать то, что ему не принадлежало. \nЯ выстрелил, он упал. Я думал — всё. А он… \nвыжил.", 0, 2); dm.AddText(c16, 8);
                DialogueLine c17 = new DialogueLine("Автор", "Из темноты коридора послышалось шарканье множества ног. И чужое, горловое мычание.", 0, 2); dm.AddText(c17, 8);
                DialogueLine c18 = new DialogueLine("Фалекс", "Быстро за ящиком, и уходим.", 30, 2); dm.AddText(c18, 8);
                DialogueLine c19 = new DialogueLine("Диана", "Бежим. или будем отстреливаться.", 10, 2); dm.AddText(c19, 8);
                
                DialogueLine dEndR1 = new DialogueLine("Диана", "Знаете, думаю вы и без нас справитесь.", 12, 3); dm.AddText(dEndR1, 9);
                DialogueLine dEndR2 = new DialogueLine("Роня", "Да, мы сами справимся.", 17, 3); dm.AddText(dEndR2, 9);
                DialogueLine dEndR3 = new DialogueLine("Автор", "Конечно они не станут помогать какому-то непонятному священнику. \nОстальные в это время тихо и не спеша отступали. \nЭмма неловко улыбнулась, подняв большие пальцы вверх, тоже пытаясь якобы поддержать. \nДинара просто начала подниматься без лишних любезностей. Недостойны.", 0, 3); dm.AddText(dEndR3, 9);
                DialogueLine dEndR4 = new DialogueLine("Роня", "в общем… да, до свидания, Фалекс.", 17, 3); dm.AddText(dEndR4, 9);
                DialogueLine dEndR5 = new DialogueLine("Автор", "Динара и Роня начали перепалку, пока все поднимались по лестнице, \nно их быстро разделила Диана.", 0, 2); dm.AddText(dEndR5, 9);
                DialogueLine dEndR6 = new DialogueLine("Диана", "заткнитесь вы обе. Ссоры нам только не хватает.", 11, 2); dm.AddText(dEndR6, 9);
                DialogueLine dEndR7 = new DialogueLine("Эмма", "В самом деле, че вы как кошка с собакой. Слушайте, что я узнала. \nЯ успела взять нужные документы и схему, пока вы спорили. \nЗдесь схема реактора. И пометка: «Второй артефакт — в 4-м блоке. \nАктивация — только при одновременном нажатии двух кнопок с интервалом \nне более 3 секунд».", 2, 2); dm.AddText(dEndR7, 9);
                DialogueLine dEndR8 = new DialogueLine("Динара", "Ого. Неожиданно. Hо нам это полезно будет.", 25, 1); dm.AddText(dEndR8, 9);
                DialogueLine dEndR9 = new DialogueLine("Эмма", "просто я делаю своё дело тихо, в отличии от некоторых.", 1, 1); dm.AddText(dEndR9, 9);
                DialogueLine dEndR10 = new DialogueLine("Диана", "Молодец, Эмма. Это нас спасет!", 12, 1); dm.AddText(dEndR10, 9);
                DialogueLine dEndR11 = new DialogueLine("Автор", "Возможно их смущало присутствие Фалекса, который даже невольно может подслушать их разговоры, \nа может ситуация просто не позволяла лишних слов. Хотя о чем это я. Компания шла какое то время молча, \nпока их не прервала Эмма. Она остановилась посреди пустого поля и громко выдохнула. \nВ этом вздохе чувствовалась тревога.  Походу шок и осознание дошли до нее только сейчас, \nв безопасной обстановке.", 1, 0); dm.AddText(dEndR11, 9);
                DialogueLine dEndR12 = new DialogueLine("Эмма", "это конец света… МЫ МОЖЕМ НЕ ДОЖИТЬ… мы… \nМЫ МОЖЕМ УМЕРЕТЬ ТУТ!", 5, 5); dm.AddText(dEndR12, 9);
                DialogueLine dEndR13 = new DialogueLine("Динара", "и не увидеть своими глазами развал СССР…", 23, 5); dm.AddText(dEndR13, 9);
                DialogueLine dEndR14 = new DialogueLine("Эмма", "И ТЕБЯ ТОЛЬКО ЭТО ВОЛНУЕТ?? ты и мы все умрем! \nМы не вернемся домой, не увидим свою семью…", 0, 5); dm.AddText(dEndR14, 9);
                DialogueLine dEndR15 = new DialogueLine("Автор", "в ее взгляде была полное отчаяние. Она не была морально готова к таким новостям.", 0, 5); dm.AddText(dEndR15, 9);
                DialogueLine dEndR16 = new DialogueLine("Роня", "не, ну Фалекс сам сказал, что это он устроил, \nраз устроил как-то, то и решит. Это ведь его проблема. \nОт нас что требуется?", 19, 5); dm.AddText(dEndR16, 9);
                DialogueLine dEndR17 = new DialogueLine("Роня", "в общем, пошлите к этому 4 блоку, \nхоть посмотрим на это нечто, что убьет нас, если убьет.", 17, 5); dm.AddText(dEndR17, 9);
                DialogueLine dEndR18 = new DialogueLine("Диана", "это может быть опасно. Может хоть придумаем, \nчто делать в том или ином случае?", 9, 5); dm.AddText(dEndR18, 9);
                DialogueLine dEndR19 = new DialogueLine("Роня", "импровизацию знаете? Ну вот и мы сымпровизируем.", 17, 5); dm.AddText(dEndR19, 9);
                DialogueLine dEndR20 = new DialogueLine("Автор", "В дороге они, конечно, смогли остудить голову Эмме, что не могло не радовать. \nНаправлялись они в сторону того самого 4 блока на Чернобыльской АЭС. По пути к ним выступило около 17 зомби. \nЭто явно напрягло девушек.", 0, 5); dm.AddText(dEndR20, 9);
                DialogueLine dEndR21 = new DialogueLine("Диана", "и сколько их еще будет? У нас патронов не хватит каждого убить. \nДа и разве мы не переубивали каждого возможного Зомби?", 11, 5); dm.AddText(dEndR21, 9);
                DialogueLine dEndR22 = new DialogueLine("Роня", "Диана, страхуй нас дробовиком. Динара, давай по быстрому этот фарш \nгнилой нарежем и пойдем дальше?", 18, 5); dm.AddText(dEndR22, 9);
                DialogueLine dEndR23 = new DialogueLine("Динара", "мне кажется это не лучшая идея.", 24, 5); dm.AddText(dEndR23, 9);
                DialogueLine dEndR24 = new DialogueLine("Роня", "ну да, лучше они нас сожрут.", 16, 5); dm.AddText(dEndR24, 9);
                DialogueLine dEndR25 = new DialogueLine("Эмма", "я вам помогу.", 4, 5); dm.AddText(dEndR25, 9);
                DialogueLine dEndR26 = new DialogueLine("Роня", "о, тем более нас трое. И снайпер в виде дианы!", 17, 5); dm.AddText(dEndR26, 9);
                DialogueLine dEndR27 = new DialogueLine("Автор", "Зомби приблизились слишком близко и времени на разговоры не было. Роня побежала первая с ножом\n в драку, остальные за ней. Диана отошла чуть назад и внимательно \nнаблюдала за каждой. Ошметки мяса, плоти и крови разлетались слишком быстро. Это было похоже на бойню. \nРоня, Эмма и Динара дрались уверенно и все же смогли победить зомби. \nДиана с дробовика парочку упырей тоже подстрелила.", 0, 5); dm.AddText(dEndR27, 9);
                DialogueLine dEndR28 = new DialogueLine("Эмма", "на нас кровь этих зомби. Вдруг мы заразимся этим хантавирусом?", 0, 5); dm.AddText(dEndR28, 9);
                DialogueLine dEndR29 = new DialogueLine("Динара", "ну… если Фалекс решит проблему, то мы просто попросим у него лекарство.", 27, 5); dm.AddText(dEndR29, 9);
                DialogueLine dEndR30 = new DialogueLine("Эмма", "а если не решит?...", 5, 5); dm.AddText(dEndR30, 9);
                DialogueLine dEndR31 = new DialogueLine("Роня", "то мертвым нам будет как-то все равно на этот вирус. \nНам в целом на все будет все равно.", 17, 5); dm.AddText(dEndR31, 9);
                DialogueLine dEndR32 = new DialogueLine("Эмма", "как оптимистично.", 0, 5); dm.AddText(dEndR32, 9);
                DialogueLine dEndR33 = new DialogueLine("Диана", "все обойдется. Вот увидите.", 12, 5); dm.AddText(dEndR33, 9);
                DialogueLine dEndR34 = new DialogueLine("Автор", "Девушки нашли брошенные жигули. Диана замкнула провода в моторе и машине завелась без ключа. \nРоня села рядом на переднее пассажирское сидение. \nДинара с Эммой сели сзади.", 0, 5); dm.AddText(dEndR34, 9);
                DialogueLine dEndR35 = new DialogueLine("Диана", "Эмма, ты как? Не бойся, мы справимся.", 9, 5); dm.AddText(dEndR35, 9);
                DialogueLine dEndR36 = new DialogueLine("Автор", "Диана спросила это тихо, чтобы их не слышали.", 0, 5); dm.AddText(dEndR36, 9);
                DialogueLine dEndR37 = new DialogueLine("Эмма", "Я не боюсь умереть, Диана. Я боюсь, что умру так и не поняв, \nзачем мы всё это делаем. Какой во всём этом смысл?", 0, 5); dm.AddText(dEndR37, 9);
                DialogueLine dEndR38 = new DialogueLine("Диана", "Смысл в том, чтобы попытаться. Даже если не получится. Чтобы потом, \nв любой другой жизни, мы могли сказать себе \n«а мы пытались»", 6, 5); dm.AddText(dEndR38, 9);
                DialogueLine dEndR39 = new DialogueLine("Эмма", "Ты правда в это веришь?", 4, 5); dm.AddText(dEndR39, 9);
                DialogueLine dEndR40 = new DialogueLine("Диана", "Нет.", 6, 5); dm.AddText(dEndR40, 9);
                DialogueLine dEndR41 = new DialogueLine("Диана", "Но это помогает мне идти дальше. И тебе советую.", 7, 5); dm.AddText(dEndR41, 9);
                DialogueLine dEndR42 = new DialogueLine("Автор", "Эмма расслабилась, но через мгновенье нахмурилась.", 0, 5); dm.AddText(dEndR42, 9);
                DialogueLine dEndR43 = new DialogueLine("Эмма", "Диана, пообещай мне, что мы вернемся, пожалуйста! Все вместе!", 4, 5); dm.AddText(dEndR43, 9);
                DialogueLine dEndR44 = new DialogueLine("Диана", "обещаю.", 12, 5); dm.AddText(dEndR44, 9);
                DialogueLine dEndR45 = new DialogueLine("Динара", "Диан, а ты водить хоть умеешь?", 24, 5); dm.AddText(dEndR45, 9);
                DialogueLine dEndR46 = new DialogueLine("Диана", "если честно, то не особо.", 13, 5); dm.AddText(dEndR46, 9);
                DialogueLine dEndR47 = new DialogueLine("Роня", "о, водитель без прав. Это именно то что нам надо! Ехала!", 17, 5); dm.AddText(dEndR47, 9);
                DialogueLine dEndR48 = new DialogueLine("Динара", "прокатимся с ветерком.", 25, 5); dm.AddText(dEndR48, 9);
                DialogueLine dEndR49 = new DialogueLine("Автор", "Эмма не нашла, что ответить, но расслабленно улыбнулась. \nДорога шла хорошо. Девушки болтали, мечтали о своем. Слова Дианы дали Эмме надежду, \nчто они справятся, она почувствовала себя увереннее.", 0, 5); dm.AddText(dEndR49, 9);
                DialogueLine dEndR50 = new DialogueLine("Эмма", "А знаете, когда мы вернёмся… Я хочу просто пойти в парк. \nЛечь на траву. Ничего не делать.", 4, 5); dm.AddText(dEndR50, 9);
                DialogueLine dEndR51 = new DialogueLine("Динара", "После апокалипсиса? \nДа ты там уснёшь и не проснёшься.", 22, 5); dm.AddText(dEndR51, 9);
                DialogueLine dEndR52 = new DialogueLine("Эмма", "Может быть. \nНо это будет лучший сон в моей жизни.", 2, 5); dm.AddText(dEndR52, 9);
                DialogueLine dEndR53 = new DialogueLine("Автор", "Эта теплая беседа продолжается, пока не появился резкий разворот на обрыве. \nУсугибило ситуацию и то, что они наткнулись на кочку, что дало машине не хилый толчок. \nСлабая дверь заднего сидения не выдержала и оторвалась. Эмма выпала следом и приземлилась туловищем на ветку, \nкоторая проткнула ее насквозь в районе груди.", 0, 5); dm.AddText(dEndR53, 9);
                DialogueLine dEndR54 = new DialogueLine("Динара", "ЭММА!", 24, 5); dm.AddText(dEndR54, 9);
                DialogueLine dEndR55 = new DialogueLine("Роня", "ДИАНА ТОРМОЗИ!", 15, 5); dm.AddText(dEndR55, 9);
                DialogueLine dEndR56 = new DialogueLine("Автор", "Машина заглохла. Трое девушек вышли из машины и увидели не самую приятную картину. \nНа последнем выдохе Эмма сказала:", 0, 5); dm.AddText(dEndR56, 9);
                DialogueLine dEndR57 = new DialogueLine("Эмма", "моя мечта… она…", 0, 5); dm.AddText(dEndR57, 9);
                DialogueLine dEndR58 = new DialogueLine("Автор", "Пару минут девушки молча в шоке смотрели на эту не новогоднюю звездочку, \nно эту тишину нарушила Роня:", 0, 5); dm.AddText(dEndR58, 9);
                DialogueLine dEndR59 = new DialogueLine("Роня", "исполнится, когда мы решим проблему…\n И как нам продолжать сюжет без гг новеллы?...", 20, 5); dm.AddText(dEndR59, 9);
                DialogueLine dEndR60 = new DialogueLine("Диана", "это явно не тот момент, когда надо шутить и ломать четвертую стену.", 11, 5); dm.AddText(dEndR60, 9);
                DialogueLine dEndR61 = new DialogueLine("Автор", "На лице было опустошение. Она изо всех сил скрывала эмоции. \nНо на пару минут не сдержадась.", 0, 5); dm.AddText(dEndR61, 9);
                DialogueLine dEndR62 = new DialogueLine("Диана", "черт! Она же реально гг и ее только начали нормально раскрывать! \nОна же явно много знала о вирусе… почему она?!", 8, 5); dm.AddText(dEndR62, 9);
                DialogueLine dEndR63 = new DialogueLine("Динара", "это да, косяк. Но ее раскроют в других ветках.", 27, 5); dm.AddText(dEndR63, 9);
                DialogueLine dEndR64 = new DialogueLine("Диана", "ты хоть понимаешь, как это прозвучало?..\n ее информация крайне важна для нас!", 11, 5); dm.AddText(dEndR64, 9);
                DialogueLine dEndR65 = new DialogueLine("Роня", "мы еще можем ей помочь?", 16, 5); dm.AddText(dEndR65, 9);
                DialogueLine dEndR66 = new DialogueLine("Динара", "не думаю… сила сюжета явно не на нашей стороне.", 21, 5); dm.AddText(dEndR66, 9);
                DialogueLine dEndR67 = new DialogueLine("Диана", "так… дамы, оплакать смерть Эммы мы еще сможем, если остановим неизбежное.", 13, 5); dm.AddText(dEndR67, 9);
                DialogueLine dEndR68 = new DialogueLine("Роня", "В любом случае… еще 40 дней ее душа будет с нами. И на зачете в июне тоже.\n дальше поведу я.", 20, 5); dm.AddText(dEndR68, 9);
                DialogueLine dEndR69 = new DialogueLine("Автор", "Спустя пару часов команда смогла пройти к этому блоку. Не без потерь, \nк сожалению, но если они вернутся в настоящее, возможно Эмма останется жива. \nРазмеры были внушительные. Роня зарядила барабан револьвера и пошла первой. \nЗа ней Динара и в конце Диана с дробовиком.\nОни шли по коридорам и вышли к какой-то ненадежной лестнице. \nТа была готова обвалиться в любой момент.", 0, 5); dm.AddText(dEndR69, 9);
                DialogueLine dEndR70 = new DialogueLine("Роня", "мы как Дима Масленников, только нас четверо. \n трое…", 20, 4); dm.AddText(dEndR70, 9);
                DialogueLine dEndR71 = new DialogueLine("Динара", "а вам не кажется что идти по этой лестнице плохая идея?", 27, 4); dm.AddText(dEndR71, 9);
                DialogueLine dEndR72 = new DialogueLine("Диана", "не из лучших уж точно.", 7, 4); dm.AddText(dEndR72, 9);
                DialogueLine dEndR73 = new DialogueLine("Автор", "Осадок от смерти Эммы остался, поэтому много разговоров было неуместно. \nНу и я не знаю, что сейчас сюда впихнуть как автор этой ветки. \nПока они шли, Диана споткнулась о торчащий гвоздь. Полетела вниз, ухватившись за периллу. \nПерила отвалилась, полетела вниз, лестница тоже начала рушиться и девушкам пришлось бежать. \nДиане неповезло, она зацепилась косичкой за торчащий гвоздь.", 0, 4); dm.AddText(dEndR73, 9);
                DialogueLine dEndR74 = new DialogueLine("Диана", "нет, я не умру от собственной косички!...", 11, 4); dm.AddText(dEndR74, 9);
                DialogueLine dEndR75 = new DialogueLine("Автор", "Диана не верила в это. В ее голосе ясно слышалась отчаяние и отрицание. \nона бросила испуганный взгляд на Роню с Динарой, пересекаясь в последние секунды \nи упала с одной из ступеней. Ее крик стремительно отдалялся. Динара монтировкой зацепилась за стену, \nРоня схватилась за Динару и так они повисли в воздухе. Лестница упала, \nоставив девушек висеть высоко над землей.", 0, 4); dm.AddText(dEndR75, 9);
                DialogueLine dEndR76 = new DialogueLine("Роня", "твою мать! Диана…\n Динара? Ты сама как?", 15, 4); dm.AddText(dEndR76, 9);
                DialogueLine dEndR77 = new DialogueLine("Динара", "я не хочу верить в то, что помимо Эммы мы потеряли и Диану...", 24, 4); dm.AddText(dEndR77, 9);
                DialogueLine dEndR78 = new DialogueLine("Роня", "давай спустимся, а там обсудим…", 20, 4); dm.AddText(dEndR78, 9);
                DialogueLine dEndR79 = new DialogueLine("Автор", "сейчас стоит думать холодной головой. Тело Дианы сейчас где-то под обломками и его не достать. \nДевушки изменили уровень наклона ножа и монтировки и соскользили по стене, \nоставляя длинные и прямые царапины. Они спустились и Динара просто села у стены, \nРоня же легла на холодный пол и выдохнула.", 0, 4); dm.AddText(dEndR79, 9);
                DialogueLine dEndR80 = new DialogueLine("Роня", "если мы решим эту проблему, то они вернутся в нашем времени по идее.", 14, 4); dm.AddText(dEndR80, 9);
                DialogueLine dEndR81 = new DialogueLine("Динара", "а может ну его?", 26, 4); dm.AddText(dEndR81, 9);
                DialogueLine dEndR82 = new DialogueLine("Автор", "Она поднялась, направив монтировку на свою голову.", 0, 4); dm.AddText(dEndR82, 9);
                DialogueLine dEndR83 = new DialogueLine("Динара", "знаешь, Ронь, может оно и к лучшему.", 22, 4); dm.AddText(dEndR83, 9);
                DialogueLine dEndR84 = new DialogueLine("Роня", "много хочешь.\n слишком далеко зашли, чтобы просто помереть. Диана и Эмма этого не хотели, \nэто случайность, а ты хочешь?", 18, 4); dm.AddText(dEndR84, 9);
                DialogueLine dEndR85 = new DialogueLine("Автор", "Роня выбила монтировку из ее рук и встала между Динарой и монтировкой.\n Где-то в душе хотелось услышать «не утрируй, \nмы еще живы так-то» но этого не произошло.", 0, 4); dm.AddText(dEndR85, 9);
                DialogueLine dEndR86 = new DialogueLine("Динара", "а смысл? Мы скорее всего заражены этим хантавирусом, \nне помрем сами-станем зомби от него.", 27, 4); dm.AddText(dEndR86, 9);
                DialogueLine dEndR87 = new DialogueLine("Автор", "Роня немного помолчала, вздохнула, собираясь с мыслями и все же сказала.", 0, 4); dm.AddText(dEndR87, 9);
                DialogueLine dEndR88 = new DialogueLine("Роня", "Пойдем. Тихо, не спеша, без суеты, как раз мы в СССР. \nЯ уверена, что осталось немного. Найдем этот несчастный второй артефакт \nи вернемся в наше время.", 17, 4); dm.AddText(dEndR88, 9);
                DialogueLine dEndR89 = new DialogueLine("Динара", "реально, чет я как дура сижу тут и нагнетаю.\nда я этот хантавирус сама заражу своей слей аурой.", 25, 4); dm.AddText(dEndR89, 9);
                DialogueLine dEndR90 = new DialogueLine("Роня", "не сомневаюсь.", 17, 4); dm.AddText(dEndR90, 9);
                DialogueLine dEndR91 = new DialogueLine("Автор", "Они дошли до той самой комнаты и Динара первой подошла к этому устройству \nи на вид все было просто и понятно.", 0, 4); dm.AddText(dEndR91, 9);
                DialogueLine dEndR92 = new DialogueLine("Динара", "а, ну так понятно что тут делать. Как там говорила Эмма? \nЦарство ей не местное… нажимаем сюда и-", 22, 4); dm.AddText(dEndR92, 9);
                DialogueLine dEndR93 = new DialogueLine("Автор", "Динара нажала кнопку и… Роня ее оттолкнула. Ржаная арматура разбила устройство.", 0, 4); dm.AddText(dEndR93, 9);
                DialogueLine dEndR94 = new DialogueLine("Динара", "это было близко. Ладно я ошиб-", 26, 4); dm.AddText(dEndR94, 9);
                DialogueLine dEndR95 = new DialogueLine("Автор", "вторая ржавая арматура пронзила девушку насквозь. \nОбе опустили взгляд вниз на торчащую насквозь железяку.", 0, 4); dm.AddText(dEndR95, 9);
                DialogueLine dEndR96 = new DialogueLine("Динара", "-лась… ох. \nа я думала эта кнопка нас спасет. Блин.", 24, 4); dm.AddText(dEndR96, 9);
                DialogueLine dEndR97 = new DialogueLine("Роня", "… \nтебя вообще не смущает, что тебя насквозь проткнула арматура? \nТЫ КРОВЬЮ ИСТЕКАЕШЬ, ДИНАРА!", 15, 4); dm.AddText(dEndR97, 9);
                DialogueLine dEndR98 = new DialogueLine("Динара", "нет Ронь, я умираю. \nБлин… надо успеть сказать какую-то крутую фразу. О, придумала.", 21, 4); dm.AddText(dEndR98, 9);
                DialogueLine dEndR99 = new DialogueLine("Динара", "с волками жить – по волчьи выть. \nА с тебя должок прощен, так и быть. ауф", 22, 4); dm.AddText(dEndR99, 9);
                DialogueLine dEndR100 = new DialogueLine("Автор", "Динара падает, глаза закрываются.  Но она добавляет", 0, 4); dm.AddText(dEndR100, 9);
                DialogueLine dEndR101 = new DialogueLine("Динара", "сюжет писать – не в жизни на зачете со стыда помирать. Свидимся на паре Алексея.", 25, 4); dm.AddText(dEndR101, 9);
                DialogueLine dEndR102 = new DialogueLine("Автор", "после этих слов все мышцы расслабляются, глаза закрываются, а тело не дышит.\n Еще пару минут Роня смотрела на это с неверием. Неужели все так тупо произошло? \nВ конце концов она не выдержала. Нажала какую-то кнопку, \nчтобы ускорить взрыв и послышался счетчик.", 0, 4); dm.AddText(dEndR102, 9);
                DialogueLine dEndR103 = new DialogueLine("Роня", "да к черту!\n давай родной не подведи!", 18, 4); dm.AddText(dEndR103, 9);
                DialogueLine dEndR104 = new DialogueLine("Автор", "она со всей силы хлопает по кнопке. она расправила руки по сторонам, \nготовясь встретить смерть в самом эпицентре взрыва.", 0, 4); dm.AddText(dEndR104, 9);
                DialogueLine dEndR105 = new DialogueLine("Автор", "Взрыв произошел. Всех четверых уже не существовало даже как пепел, \nа Фалекс, услышав взрыв посмотрел в окно, развернулся и эпично пошел спиной к взрыву, зная, \nчто сейчас умрет и сделать это надо эпично.", 0, 4); dm.AddText(dEndR105, 9);
                DialogueLine dEndR106 = new DialogueLine("Фалекс", "сюжет слили. Понятно. Ну ладно, зато эффектно.", 30, 4); dm.AddText(dEndR106, 9);
                DialogueLine dEndR107 = new DialogueLine("Автор", "Через мгновение Советского Союза на стало. А вскоре и всего мира не стало.\n Конец.\nПоздравляем, вы убили своих друзей, себя и весь мир!", 0, 4); dm.AddText(dEndR107, 9);
               
                DialogueLine lineB1 = new DialogueLine("Автор", "День второй. Вечер. \nЧеловек в углу дышал тяжело, но ровно. Эмма стояла у стола, глядя на шкатулку с часами. \nЕй хотелось взять их, повернуть стрелки, попробовать вернуться. \nНо что-то останавливало.", 0, 0); dm.AddText(lineB1, 10);
                DialogueLine lineB2 = new DialogueLine("Эмма", "Я не буду. Слишком рискованно. В прошлый раз мы чудом не погибли. \nА вдруг в следующий раз выбросит в реактор \nили в открытый космос?", 5, 0); dm.AddText(lineB2, 10);
                DialogueLine lineB3 = new DialogueLine("Диана", "Разумно, наша единственная связь с будущим. \nЛомать их, не понимая как — самоубийство.", 6, 0); dm.AddText(lineB3, 10);
                DialogueLine lineB4 = new DialogueLine("Роня", "Тогда что будем делать?", 19, 0); dm.AddText(lineB4, 10);
                DialogueLine lineB5 = new DialogueLine("Диана", "Ждать. Наблюдать за ним. Возможно, он очнётся и расскажет что-то сам.", 7, 0); dm.AddText(lineB5, 10);
                DialogueLine lineB6 = new DialogueLine("Автор", "Они устроились на ночлег. Динара погасила горелку, оставив лишь тусклый фонарь. \nЭмма села рядом с пациентом, сжимая его холодную ладонь. Тот не приходил в себя, но дышал.\nНочь прошла в тревожном полузабытьи.\nДень третий. Утро.\nПациент не проснулся. Эмма потрогала его лоб — горячий. Температура снова подскочила. \nПульс нитевидный. Она попыталась дать ему воды — он не глотал.", 0, 0); dm.AddText(lineB6, 10);
                DialogueLine lineB7 = new DialogueLine("Динара", "Ему хуже.", 27, 0); dm.AddText(lineB7, 10);
                DialogueLine lineB8 = new DialogueLine("Динара", "Гораздо хуже. \nЕсли не придет в себя до вечера, он не выживет.", 24, 0); dm.AddText(lineB8, 10);
                DialogueLine lineB9 = new DialogueLine("Роня", "Может, попробовать вколоть ещё одно лекарство из аптечки?", 16, 0); dm.AddText(lineB9, 10);
                DialogueLine lineB10 = new DialogueLine("Диана", "Нет. Первая инъекция уже почти убила его. Вторая точно добьёт.", 21, 0); dm.AddText(lineB10, 10);
                DialogueLine lineB11 = new DialogueLine("Автор", "Они остались в подвале. Ждали. К вечеру пациент забился в конвульсиях. \nЭмма пыталась удержать его, но он выгнулся дугой, \nизо рта пошла чёрная пена, а затем он обмяк.", 0, 0); dm.AddText(lineB11, 10);
                DialogueLine lineB12 = new DialogueLine("Динара", "Не дышит. Сердце остановилось.", 23, 0); dm.AddText(lineB12, 10);
                DialogueLine lineB13 = new DialogueLine("Автор", "Эмма попыталась сделать искусственное дыхание, массаж сердца — бесполезно. \nЧерез десять минут Динара молча отстранила её.", 0, 0); dm.AddText(lineB13, 10);
                DialogueLine lineB14 = new DialogueLine("Эмма", "Всё.", 0, 0); dm.AddText(lineB14, 10);
                DialogueLine lineB15 = new DialogueLine("Автор", "Они сидели вокруг мёртвого тела. Тишину нарушал только ветер за разбитыми окнами.", 0, 0); dm.AddText(lineB15, 10);
                DialogueLine lineB16 = new DialogueLine("Роня", "Осмотрим его. Может, при нём есть документы. \nМы даже не знаем, кто он.", 14, 0); dm.AddText(lineB16, 10);
                DialogueLine lineB17 = new DialogueLine("Автор", "Динара обыскала карманы его халата. В одном нашлась старая авторучка, \nв другом — небольшой потрёпанный блокнот в кожаном переплёте.", 0, 0); dm.AddText(lineB17, 10);
                DialogueLine lineB18 = new DialogueLine("Динара", "Это.", 27, 0); dm.AddText(lineB18, 10);
                DialogueLine lineB19 = new DialogueLine("Автор", "Она протягивает блокнот Эмме. \nЭмма открыла. Страницы были исписаны мелким почерком, формулы, схемы. \nНо не это привлекло её внимание. На одной из страниц был рисунок: \nтри вертикальные линии, дуга сверху, и цифры: 7, 3, 15.\nА ниже — подпись: «Код к часам. Повернуть в последовательности: 7, 3, 15. \nТогда откроется путь к церкви. Ф.»", 0, 0); dm.AddText(lineB19, 10);
                DialogueLine lineB20 = new DialogueLine("Эмма", "Часы. Те самые, в шкатулке. Код.", 2, 0); dm.AddText(lineB20, 10);
                DialogueLine lineB21 = new DialogueLine("Диана", "Значит, он знал. Знал о часах и о том, как они работают.", 9, 0); dm.AddText(lineB21, 10);
                DialogueLine lineB22 = new DialogueLine("Роня", "И работал с Фалексом.", 18, 0); dm.AddText(lineB22, 10);
                DialogueLine lineB23 = new DialogueLine("Автор", "Динара перевернула несколько страниц. Нашлась карта-схема с отметкой: \n«Улица Курчатова, 14, церковь. Под алтарём — записи Фалекса. Не доверять священнику».", 0, 0); dm.AddText(lineB23, 10);
                DialogueLine lineB24 = new DialogueLine("Диана", "Он нас туда посылает. Даже мёртвый.", 13, 0); dm.AddText(lineB24, 10);
                DialogueLine lineB25 = new DialogueLine("Роня", "Или его убили, чтобы мы нашли эти записи.", 16, 0); dm.AddText(lineB25, 10);
                DialogueLine lineB26 = new DialogueLine("Автор", "Эмма закрыла блокнот. На обложке были выцарапаны те же цифры: 7-3-15.", 0, 0); dm.AddText(lineB26, 10);
                DialogueLine lineB27 = new DialogueLine("Эмма", "Мы должны идти туда. Это единственный способ понять, что здесь произошло. \nИ, возможно, вернуться домой.", 4, 0); dm.AddText(lineB27, 10);
                DialogueLine lineB28 = new DialogueLine("Динара", "А тело?", 26, 0); dm.AddText(lineB28, 10);
                DialogueLine lineB29 = new DialogueLine("Эмма", "Похороним позже. Сначала — часы и код.", 1, 0); dm.AddText(lineB29, 10);
                DialogueLine lineB30 = new DialogueLine("Автор", "Эмма взяла шкатулку. Часы по-прежнему молчали, застыв на 26 апреля 01:23.", 0, 0); dm.AddText(lineB30, 10);
                DialogueLine lineB31 = new DialogueLine("Эмма", "Он сказал «повернуть в последовательности 7, 3, 15». \nНо в каком направлении? По часовой или против?", 4, 0); dm.AddText(lineB31, 10);
                DialogueLine lineB32 = new DialogueLine("Диана", "Будем разбираться на местe. Идём завтра на рассвете. А пока — надо решить, \nчто делать с телом и с самими часами.", 6, 0); dm.AddText(lineB32, 10);
                
                DialogueLine endD1 = new DialogueLine("Диана", "Уходим!", 8, 3); dm.AddText(endD1, 11);
                DialogueLine endD2 = new DialogueLine("Автор", "Фалекс замешкался, глядя на тело Кольки, но Роня схватила его за рукав \nи потащила за собой. Они выбежали из склада, захлопнув дверь. С той стороны заскреблись, \nзавыли — но не пробили. Фалекс стоял, тяжело дыша, \nи смотрел на дверь.", 0, 3); dm.AddText(endD2, 11);
                DialogueLine endD3 = new DialogueLine("Фалекс", "Компонент остался там.", 35, 3); dm.AddText(endD3, 11);
                DialogueLine endD4 = new DialogueLine("Диана", "Ты живой остался. Это важнее.", 10, 3); dm.AddText(endD4, 11);
                DialogueLine endD5 = new DialogueLine("Автор", "Фалекс ничего не сказал. Он развернулся и пошёл к церкви. Молча. Девушки переглянулись и двинулись за ним.\nФалекс молча смешивал что-то из остатков реагентов, но было видно \nбез того компонента его зелье не полноценно.", 0, 3); dm.AddText(endD5, 11);
                DialogueLine endD6 = new DialogueLine("Фалекс", "Не получится. Без ампул со склада противоядие не приготовить.", 29, 3); dm.AddText(endD6, 11);
                DialogueLine endD7 = new DialogueLine("Диана", "Значит, будем искать другой путь.", 12, 3); dm.AddText(endD7, 11);
                DialogueLine endD8 = new DialogueLine("Фалекс", "Другого нет. Только через четвёртый блок. Только через установку.", 31, 3); dm.AddText(endD8, 11);
                DialogueLine endD9 = new DialogueLine("Эмма", "Какую установку?", 4, 3); dm.AddText(endD9, 11);
                DialogueLine endD10 = new DialogueLine("Автор", "Фалекс посмотрел на неё — устало, почти безразлично.", 0, 3); dm.AddText(endD10, 11);
                DialogueLine endD11 = new DialogueLine("Фалекс", "Идите за мной.", 35, 3); dm.AddText(endD11, 11);
                DialogueLine endD12 = new DialogueLine("Автор", "Он привёл их в дальнюю часть подвала, к массивной гермодвери. \nНа ней, вместо замка, мерцал маленький экран. \nПадающие фигуры. Тетрис.", 0, 3); dm.AddText(endD12, 11);
                DialogueLine endD13 = new DialogueLine("Эмма", "…Вы серьёзно? Мы сейчас умрём из-за игры?", 0, 3); dm.AddText(endD13, 11);
                DialogueLine endD14 = new DialogueLine("Динара", "Не умрём. Отойди.", 26, 3); dm.AddText(endD14, 11);
                DialogueLine endD15 = new DialogueLine("Автор", "Она встала перед экраном. Все было нереально быстро.", 0, 3); dm.AddText(endD15, 11);
                DialogueLine endD16 = new DialogueLine("Эмма", "Это не игра… Это тест реакции.", 5, 3); dm.AddText(endD16, 11);
                DialogueLine endD17 = new DialogueLine("Динара", "Тогда не мешай.", 21, 3); dm.AddText(endD17, 11);
                DialogueLine go1 = new DialogueLine("Автор", "У всех замирает сердце. Раздается щелчек.", 0, 3); dm.AddText(go1, 13);
                DialogueLine go2 = new DialogueLine("Динара","Что это?", 26, 3); dm.AddText(go2, 13);
                DialogueLine go3 = new DialogueLine("Автор", "Появляются звуки похожие на таймер. Все понимают \nк чему это ведет. Сработала аварийная система.", 0, 3); dm.AddText(go3, 13);
                DialogueLine go4 = new DialogueLine("Эмма", "Простите меня за все.", 1, 3); dm.AddText(go4, 13);
                DialogueLine go5 = new DialogueLine("Автор", "Наступила тишина. Никто не произнёс ни слова. Яркая вспышка поглотила подвал. А затем — ничего. \nВсе погибают и от церкви не остается почти ничего.Мир остается прежним. \nЗаражённых становилось всё больше, и вскоре правительство перестало скрывать происходящее. \nЧерез радиосигналы людям внушали покорность, подавляя волю и мысли.\nОбразуется целые колонии зараженных, беспрекословно выполняющих приказы. Сопротивляться было некому. \nЧеловечество выжило. Но люди перестали быть людьми.", 0, 3); dm.AddText(go5, 13);
                DialogueLine endD18 = new DialogueLine("Автор", "ЩЕЛЧОК.\nДверь открылась.\nУстановка.\nИзнутри ударил холодный воздух.", 0, 3); dm.AddText(endD18, 11);
                DialogueLine endD19 = new DialogueLine("Эмма", "Формалин… и озон. Значит, тут было напряжение. Большое.", 3, 3); dm.AddText(endD19, 11);
                DialogueLine endD20 = new DialogueLine("Автор", "Они переглянулись и начали спускаться.\nПодвал оказался не просто лабораторией. Это была замкнутая система. Толстые стены, гермодвери, генераторы, кабели. \nВ центре — кольцевая установка с креслами и фиксаторами.\nНа койках лежали тела. Разрезанные. Сшитые. Подключённые к датчикам. Над висками — электроды.\nНекоторые… дышали. Один повернул голову.", 0, 3); dm.AddText(endD20, 11);
                DialogueLine endD21 = new DialogueLine("Какой-то бедолага", "…не… уходите…", 0, 3); dm.AddText(endD21, 11);
                DialogueLine endD22 = new DialogueLine("Автор", "Диана замерла.", 0, 3); dm.AddText(endD22, 11);
                DialogueLine endD23 = new DialogueLine("Диана", "Он в сознании.", 9, 3); dm.AddText(endD23, 11);
                DialogueLine endD24 = new DialogueLine("Эмма", "Частично. Их удерживают между состояниями.", 1, 3); dm.AddText(endD24, 11);
                DialogueLine endD25 = new DialogueLine("Автор", "Она быстро осматривала установку.", 0, 3); dm.AddText(endD25, 11);
                DialogueLine endD26 = new DialogueLine("Эмма", "Он не изучал тела. Он изучал сигналы.", 2, 3); dm.AddText(endD26, 11);
                DialogueLine endD27 = new DialogueLine("Какой-то бедолага", "Нет. Я изучал пригодность.", 0, 3); dm.AddText(endD27, 11);
                DialogueLine endD28 = new DialogueLine("Автор", "Они обернулись.\nФалекс стоял в проходе. Слишком спокойный. Слишком чистый. На руках — засохшая кровь.\nОн прошёл между койками, как по коридору.", 0, 3); dm.AddText(endD28, 11);
                DialogueLine endD29 = new DialogueLine("Фалекс", "Вы всё ещё называете их людьми. Это ошибка.", 30, 3); dm.AddText(endD29, 11);
                DialogueLine endD30 = new DialogueLine("Автор", "Он резко нажал пальцами в открытую рану одного из заражённых. \nТело дёрнулось. Без крика.", 0, 3); dm.AddText(endD30, 11);
                DialogueLine endD31 = new DialogueLine("Фалекс", "Боль есть. Паники нет. Лишнее убрано.", 28, 3); dm.AddText(endD31, 11);
                DialogueLine endD32 = new DialogueLine("Автор", "Динара отшатнулась.", 0, 3); dm.AddText(endD32, 11);
                DialogueLine endD33 = new DialogueLine("Динара", "Ты больной.", 24, 3); dm.AddText(endD33, 11);
                DialogueLine endD34 = new DialogueLine("Фалекс", "Нет. Я последовательный.", 31, 3); dm.AddText(endD34, 11);
                DialogueLine endD35 = new DialogueLine("Автор", "Он указал на ряд коек.", 0, 3); dm.AddText(endD35, 11);
                DialogueLine endD36 = new DialogueLine("Фалекс", "Эти — нестабильны. Брак. Эти — лучше. Реагируют. \nА некоторые… — он посмотрел на Эмму", 35, 3); dm.AddText(endD36, 11);
                DialogueLine endD37 = new DialogueLine("Фалекс", "Таких нужно использовать.", 32, 3); dm.AddText(endD37, 11);
                DialogueLine endD38 = new DialogueLine("Автор", "Роня подняла револьвер.", 0, 3); dm.AddText(endD38, 11);
                DialogueLine endD39 = new DialogueLine("Роня", "Ещё шаг — и ты труп.", 18, 3); dm.AddText(endD39, 11);
                DialogueLine endD40 = new DialogueLine("Автор", "Фалекс даже не остановился.", 0, 3); dm.AddText(endD40, 11);
                DialogueLine endD41 = new DialogueLine("Фалекс", "Сила — это примитивно. Контроль — это когда объект сам хочет подчиняться.", 33, 3); dm.AddText(endD41, 11);
                DialogueLine endD42 = new DialogueLine("Автор", "Он коснулся установки.", 0, 3); dm.AddText(endD42, 11);
                DialogueLine endD43 = new DialogueLine("Фалекс", "Здесь происходит отбор. Давление. Усиление.", 32, 3); dm.AddText(endD43, 11);
                DialogueLine endD44 = new DialogueLine("Динара", "Ты устроил здесь лагерь.", 26, 3); dm.AddText(endD44, 11);
                DialogueLine endD45 = new DialogueLine("Фалекс", "Это фильтр.", 31, 3); dm.AddText(endD45, 11);
                DialogueLine endD46 = new DialogueLine("Автор", "Тишина.", 0, 3); dm.AddText(endD46, 11);
                DialogueLine endD47 = new DialogueLine("Фалекс", "Вирус — это шанс. Убрать лишнее. Оставить только тех, кто выдерживает себя.", 32, 3); dm.AddText(endD47, 11);
                DialogueLine endD48 = new DialogueLine("Автор", "Эмма подошла к установке.", 0, 3); dm.AddText(endD48, 11);
                DialogueLine endD49 = new DialogueLine("Эмма", "Это не просто контроль.", 3, 3); dm.AddText(endD49, 11);
                DialogueLine endD50 = new DialogueLine("Автор", "Она провела рукой по панели.", 0, 3); dm.AddText(endD50, 11);
                DialogueLine endD51 = new DialogueLine("Эмма", "Это резонансная камера.", 2, 3); dm.AddText(endD51, 11);
                DialogueLine endD52 = new DialogueLine("Автор", "Все посмотрели на неё.", 0, 3); dm.AddText(endD52, 11);
                DialogueLine endD53 = new DialogueLine("Эмма", "После аварии радиация стала нестабильной. Мы пытались использовать её для работы с мозгом.", 1, 3); dm.AddText(endD53, 11);
                DialogueLine endD54 = new DialogueLine("Автор", "Она указала на электроды.", 0, 3); dm.AddText(endD54, 11);
                DialogueLine endD55 = new DialogueLine("Эмма", "Вирус усиливает внутренние состояния. А здесь… их фиксируют.", 2, 3); dm.AddText(endD55, 11);
                DialogueLine endD56 = new DialogueLine("Динара", "Как?", 23, 3); dm.AddText(endD56, 11);
                DialogueLine endD57 = new DialogueLine("Эмма", "Через перегрузку поля. Электромагнитный импульс синхронизируется с мозгом.", 1, 3); dm.AddText(endD57, 11);
                DialogueLine endD58 = new DialogueLine("Эмма", "И система пересобирает состояние.", 3, 3); dm.AddText(endD58, 11);
                DialogueLine endD59 = new DialogueLine("Роня", "Проще.", 16, 3); dm.AddText(endD59, 11);
                DialogueLine endD60 = new DialogueLine("Автор", "Эмма посмотрела на кнопку.", 0, 3); dm.AddText(endD60, 11);
                DialogueLine endD61 = new DialogueLine("Эмма", " Мы не перемещаемся. Мы заставляем себя соответствовать более позднему состоянию мира.", 3, 3); dm.AddText(endD61, 11);
                DialogueLine endD62 = new DialogueLine("Диана", "То есть… вперёд во времени?", 9, 3); dm.AddText(endD62, 11);
                DialogueLine endD63 = new DialogueLine("Эмма", "Да. Но не полностью.", 2, 3); dm.AddText(endD63, 11);
                DialogueLine endD64 = new DialogueLine("Роня", "Цена?", 19, 3); dm.AddText(endD64, 11);
                DialogueLine endD65 = new DialogueLine("Эмма", "Слабые связи стираются. Память. Эмоции. Часть личности.", 2, 3); dm.AddText(endD65, 11);
                DialogueLine endD66 = new DialogueLine("Автор", "Фалекс тихо добавил:", 0, 3); dm.AddText(endD66, 11);
                DialogueLine endD67 = new DialogueLine("Фалекс", "Именно так и должно быть. После перехода вы станете чище. Без лишнего.", 31, 3); dm.AddText(endD67, 11);
                DialogueLine endD68 = new DialogueLine("Автор", "Динара сжала руку Эммы.", 0, 3); dm.AddText(endD68, 11);
                DialogueLine endD69 = new DialogueLine("Эмма", "Я не хочу быть «чище». Я хочу быть собой.", 4, 3); dm.AddText(endD69, 11);
                DialogueLine endD70 = new DialogueLine("Фалекс", "Тогда ты не пройдёшь отбор.", 32, 3); dm.AddText(endD70, 11);
                DialogueLine endD71 = new DialogueLine("Автор", "Диана посмотрела на всех.", 0, 3); dm.AddText(endD71, 11);
                DialogueLine endD72 = new DialogueLine("Диана", "У нас нет времени. Либо здесь, либо риск.", 11, 3); dm.AddText(endD72, 11);
                DialogueLine endD73 = new DialogueLine("Динара", "Там может ничего не быть.", 26, 3); dm.AddText(endD73, 11);
                DialogueLine endD74 = new DialogueLine("Диана", "Здесь уже почти ничего нет.", 7, 3); dm.AddText(endD74, 11);
                DialogueLine endD75 = new DialogueLine("Автор", "Пауза.\nЭмма протянула руку.", 0, 3); dm.AddText(endD75, 11);
                DialogueLine endD76 = new DialogueLine("Эмма", "Держимся вместе. Это может сохранить нас.", 3, 3); dm.AddText(endD76, 11);
                DialogueLine endD77 = new DialogueLine("Автор", "Они взялись за руки. Роня. Динара. Эмма. Диана. Фалекс стоял напротив.", 0, 3); dm.AddText(endD77, 11);
                DialogueLine endD78 = new DialogueLine("Фалекс", "Вы всё равно потеряете себя", 28, 3); dm.AddText(endD78, 11);
                DialogueLine endD79 = new DialogueLine("Эмма", "Может быть. Но не станем такими, как ты.", 1, 3); dm.AddText(endD79, 11);
                DialogueLine endD80 = new DialogueLine("Автор", "Она нажала кнопку. \nСначала — вибрация. Потом давление. Воздух стал плотным. Цвета исчезли. Остались серые тени.\n Мысли начали распадаться. Лица. Голоса. Воспоминания.", 0, 3); dm.AddText(endD80, 11);
                DialogueLine endD81 = new DialogueLine("Диана", "ДЕРЖИТЕСЬ!", 8, 3); dm.AddText(endD81, 11);
                DialogueLine endD82 = new DialogueLine("Автор", "Они сжимали руки.\nФалекс не двигался. Не держался ни за что. Только смотрел. Спокойно. Будто он уже прошёл этот отбор.\nИ в какой-то момент — всё схлопнулось.", 0, 3); dm.AddText(endD82, 11);
                DialogueLine endD83 = new DialogueLine("Автор", "НОВОЕ ВРЕМЯ\nТишина.\nЭмма открыла глаза.\nПодвал был тем же. Но старее. Пыль. Трещины. Ржавчина. \nТела на койках — высохшие. Мёртвые. По-настоящему.", 0, 7); dm.AddText(endD83, 11);
                DialogueLine endD84 = new DialogueLine("Динара", "…мы живы?", 24, 7); dm.AddText(endD84, 11);
                DialogueLine endD85 = new DialogueLine("Роня", "Да", 16, 7); dm.AddText(endD85, 11);
                DialogueLine endD86 = new DialogueLine("Диана", "Сколько прошло?", 13, 7); dm.AddText(endD86, 11);
                DialogueLine endD87 = new DialogueLine("Автор", "Никто не знал.\nОни поднялись наверх. Церковь разрушена. Деревья проросли сквозь бетон. Ни звука. Ни заражённых.", 0, 7); dm.AddText(endD87, 11);
                DialogueLine endD88 = new DialogueLine("Эмма", "Это плохо.", 0, 7); dm.AddText(endD88, 11);
                DialogueLine endD89 = new DialogueLine("Динара", "Почему?", 27, 7); dm.AddText(endD89, 11);
                DialogueLine endD90 = new DialogueLine("Эмма", "Потому что кто-то должен был выжить.", 5, 7); dm.AddText(endD90, 11);
                DialogueLine endD91 = new DialogueLine("Автор", "В убежище они нашли телевизор. Старый. Рабочий. Экран загорелся не сразу.", 0, 7); dm.AddText(endD91, 11);
                DialogueLine endD92 = new DialogueLine("Голос из телека", "…Советский Союз… прекращает своё существование…", 0, 7); dm.AddText(endD92, 11);
                DialogueLine endD93 = new DialogueLine("Диана", "Получилось.", 12, 7); dm.AddText(endD93, 11);
                DialogueLine endD94 = new DialogueLine("Автор", "Роня провела рукой по лицу.", 0, 7); dm.AddText(endD94, 11);
                DialogueLine endD95 = new DialogueLine("Роня", "Мы перескочили.", 16, 7); dm.AddText(endD95, 11);
                DialogueLine endD96 = new DialogueLine("Эмма", "Да. В стабильное состояние.", 4, 7); dm.AddText(endD96, 11);
                DialogueLine endD97 = new DialogueLine("Динара", "А вирус?", 21, 7); dm.AddText(endD97, 11);
                DialogueLine endD98 = new DialogueLine("Эмма", "Он часть системы.", 3, 7); dm.AddText(endD98, 11);
                DialogueLine endD99 = new DialogueLine("Динара", "Значит, он с нами.\r\n", 23, 7); dm.AddText(endD99, 11);
                DialogueLine endD100 = new DialogueLine("Роня", "Я… …я не помню лицо матери.", 15, 7); dm.AddText(endD100, 11);
                DialogueLine endD101 = new DialogueLine("Автор", "Никто не ответил.\nЦена.\nСнаружи был новый мир. Тихий. Пустой.", 0, 7); dm.AddText(endD101, 11);
                DialogueLine endD102 = new DialogueLine("Диана", "Значит\n либо мы последние…", 11, 7); dm.AddText(endD102, 11);
                DialogueLine endD103 = new DialogueLine("Эмма", "…либо первые.", 0, 7); dm.AddText(endD103, 11);
                DialogueLine endD104 = new DialogueLine("Автор", "Телевизор шипел.\nА где-то глубоко внутри них… что-то осталось. И что-то — исчезло навсегда.", 0, 7); dm.AddText(endD104, 11);
              
                DialogueLine endG1 = new DialogueLine("Диана", "Прорываемся!", 8, 3); dm.AddText(endG1, 12);
                DialogueLine endG2 = new DialogueLine("Автор", "Они рванули вперёд. Фалекс бежал первым, за ним Эмма, Роня и Динара прикрывали сзади. \nТвари выскакивали из темноты — Эмма стреляла не целясь, только бы отбросить их. \nДинара отбивалась монтировкой, Роня работала револьвером. Ящик стоял в конце коридора на ржавом стеллаже. \nФалекс схватил его, вытряхнул ампулы в карман рясы.", 0, 3); dm.AddText(endG2, 12);
                DialogueLine endG3 = new DialogueLine("Фалекс", "Есть!", 31, 5); dm.AddText(endG3, 12);
                DialogueLine endG4 = new DialogueLine("Диана", "Назад!", 10, 5); dm.AddText(endG4, 12);
                DialogueLine endG5 = new DialogueLine("Автор", "Они побежали обратно. Твари лезли отовсюду, но группа действовала слаженно. \nДверь склада захлопнулась за ними, Фалекс провернул ключ в замке. С той стороны заскреблись, \nзавыли, но не пробили.", 0, 5); dm.AddText(endG5, 12);
                DialogueLine endG6 = new DialogueLine("Роня", "Живы.", 17, 5); dm.AddText(endG6, 12);
                DialogueLine endG7 = new DialogueLine("Автор", "Фалекс кивнул, не говоря ни слова, и быстро зашагал к церкви.\nВ подвале церкви:\nФалекс работал быстро. Смешивал, нагревал, переливал. \nДевушки стояли в стороне, не мешая.", 0, 5); dm.AddText(endG7, 12);
                DialogueLine endG8 = new DialogueLine("Фалекс", "Готово. Теперь к блоку.", 35, 5); dm.AddText(endG8, 12);
                DialogueLine endG9 = new DialogueLine("Эмма", "Что там?", 2, 5); dm.AddText(endG9, 12);
                DialogueLine endG10 = new DialogueLine("Фалекс", "Увидите.", 32, 5); dm.AddText(endG10, 12);
                DialogueLine endG11 = new DialogueLine("Автор", "Они двинулись к четвёртому энергоблоку. Территория станции кишела тварями — теми, кто был заражён, теми, кто превратился. \nОтбивались на каждом шагу. Динара потеряла монтировку, Роня расстреляла почти все патроны, Эмма выбилась из сил, \nно Фалекс вёл их вперёд, не оглядываясь.\nОни прорвались.\nВнутри блока, в пультовой, Фалекс влил жидкость в главный распределительный щит. Что-то загудело, \nзамигало — и по всем приборам поползли зелёные индикаторы.", 0, 4); dm.AddText(endG11, 12);
                DialogueLine endG12 = new DialogueLine("Фалекс", "Готово", 30, 4); dm.AddText(endG12, 12);
                DialogueLine endG13 = new DialogueLine("Диана", "Что вы сделали?", 9, 4); dm.AddText(endG13, 12);
                DialogueLine endG14 = new DialogueLine("Фалекс", "Остановил цепную реакцию. Завтрашнего взрыва не будет. \nИ вирус не распространится.", 28, 4); dm.AddText(endG14, 12);
                DialogueLine endG15 = new DialogueLine("Автор", "Эмма не знала, чему верить, но смотреть на его лицо — усталое, но спокойное — хотелось верить.\nВозвращение\nЧасы на её груди щёлкнули. Крест нагрелся, воздух задрожал.", 0, 4); dm.AddText(endG15, 12);
                DialogueLine endG16 = new DialogueLine("Эмма", "Держитесь!", 5, 4); dm.AddText(endG16, 12);
                DialogueLine endG17 = new DialogueLine("Автор", "Вспышка. Провал.\nОни упали на мягкую траву. Солнце. Тишина. Никаких сирен, никакого запаха гари.\nЭмма открыла глаза. Вокруг — восстановленный Чернобыль, каким они его знали. \nЧистый, живой, без тварей.", 0, 6); dm.AddText(endG17, 12);
                DialogueLine endG18 = new DialogueLine("Роня", "Получилось.", 16, 6); dm.AddText(endG18, 12);
                DialogueLine endG19 = new DialogueLine("Диана", "Получилось.", 12, 6); dm.AddText(endG19, 12);
                DialogueLine endG20 = new DialogueLine("Автор", "Динара лежала на спине и смеялась.\nЭмма перевела взгляд на Фалекса. Он стоял в двух шагах, оглядываясь, \nи вдруг улыбнулся. Не пусто, не фальшиво — первый раз по-настоящему.", 0, 6); dm.AddText(endG20, 12);
                DialogueLine endG21 = new DialogueLine("Эмма", "Вы… вы с нами. — Вы не остались в прошлом.", 4, 6); dm.AddText(endG21, 12);
                DialogueLine endG22 = new DialogueLine("Фалекс", "Не остался. Я всегда был из вашего времени.", 31, 6); dm.AddText(endG22, 12);
                DialogueLine endG23 = new DialogueLine("Динара", "Что?", 26, 6); dm.AddText(endG23, 12);
                DialogueLine endG24 = new DialogueLine("Фалекс", "Моя ряса, моя церковь — это прикрытие. Настоящий я — сотрудник института времени. \nНас отправили в прошлое, чтобы предотвратить катастрофу. Я потерял группу, \nпришлось действовать одному. Часы с крестом — наша разработка.", 28, 6); dm.AddText(endG24, 12);
                DialogueLine endG25 = new DialogueLine("Эмма", "То есть вы — наш коллега?", 2, 6); dm.AddText(endG25, 12);
                DialogueLine endG26 = new DialogueLine("Фалекс", "Можно и так сказать.", 30, 6); dm.AddText(endG26, 12);
                DialogueLine endG27 = new DialogueLine("Автор", "Они сидели на траве, смотрели на чистое небо и не могли поверить. Всё закончилось. \nМиссия выполнена. Они спасли не только себя — спасли мир.", 0, 6); dm.AddText(endG27, 12);
                DialogueLine endG28 = new DialogueLine("Диана", "С возвращением, команда.", 12, 6); dm.AddText(endG28, 12);
                DialogueLine endG29 = new DialogueLine("Автор", "И они засмеялись. Все вместе.\n Эпилог.\n2067 год. Чернобыль процветает. Аварии не было. Вируса не существует. \nЛюди живут, работают, радуются жизни.\nЭмма, Диана, Роня, Динара и Фалекс стали лучшей командой \nИнститута времени. Их отправили в новую командировку — в другой век, на другую миссию.\nНо это уже совсем другая история.", 0, 6); dm.AddText(endG29, 12);

            }
        }
        public class DialogueLine
        {
            public string Name { get; set; }
            public string Text { get; set; }
            public int indIm { get; set; }
            public int intImB { get; set; }

            public DialogueLine(string name, string text, int imageIndex, int backgroundIndex)
            {
                Text = text;
                Name = name;
                indIm = imageIndex;
                intImB = backgroundIndex;
            }

        }
        public class DialogueManager
        {
            private List<string> history = new List<string>();
            private List<List<DialogueLine>> listOfLists = new List<List<DialogueLine>>();

            public void AddText(DialogueLine line, int a)
            {
                while (listOfLists.Count <= a)
                {
                    listOfLists.Add(new List<DialogueLine>());
                }
                listOfLists[a].Add(line);
            }
            
            public List<DialogueLine> GetDialog(int a)
            {
                return listOfLists[a];
            }
            public void TextWindow(DialogueLine line)
            {
                string kukaracha = line.Name + ": " + line.Text;
                history.Add(kukaracha);
            }
            public List<string> GetHistory()
            {
                return history;
            }
            public void ClearHistory()
            {
                history.Clear();
            }

        }
    }
}